export const FME_FLASHCARDS: FMEFlashcard[] = [
  // ═══════════════════════════════════════════════════════════════
  // TOPIC 0 — Mathematics (25 hand-crafted + formulas)
  // ═══════════════════════════════════════════════════════════════
  { id: 1, front: "What is the derivative of x^n?", back: "n·x^(n-1) — The power rule is the most commonly used derivative rule on the FE exam.", domain: "topic0", domainName: "Mathematics", category: "formula", topics: ["Calculus"] },
  { id: 2, front: "State the chain rule for derivatives.", back: "dy/dx = (dy/du)·(du/dx) — Differentiate the outer function, then multiply by the derivative of the inner function.", domain: "topic0", domainName: "Mathematics", category: "formula", topics: ["Calculus"] },
  { id: 3, front: "What is integration by parts?", back: "∫u dv = uv - ∫v du — Use LIATE to choose u: Log, Inverse trig, Algebraic, Trig, Exponential.", domain: "topic0", domainName: "Mathematics", category: "formula", topics: ["Calculus"] },
  { id: 4, front: "How do you find the volume of revolution using the disk method?", back: "V = π∫[f(x)]² dx — Rotate a function about an axis; each slice is a disk of radius f(x).", domain: "topic0", domainName: "Mathematics", category: "concept", topics: ["Calculus"] },
  { id: 5, front: "What does a zero determinant mean for a matrix?", back: "The matrix is singular (not invertible). The system either has no solution or infinitely many solutions.", domain: "topic0", domainName: "Mathematics", category: "concept", topics: ["Linear Algebra"] },
  { id: 6, front: "How do you find eigenvalues?", back: "Solve det(A - λI) = 0 — The characteristic equation. For 2×2: λ² - trace·λ + det = 0.", domain: "topic0", domainName: "Mathematics", category: "formula", topics: ["Linear Algebra"] },
  { id: 7, front: "What is Cramer's Rule?", back: "x_i = det(A_i)/det(A) — Replace column i of A with vector b, take determinant, divide by det(A). Efficient for 2×2 and 3×3.", domain: "topic0", domainName: "Mathematics", category: "formula", topics: ["Linear Algebra"] },
  { id: 8, front: "What is a separable ODE and how do you solve it?", back: "Form: dy/dx = f(x)·g(y). Separate: dy/g(y) = f(x)dx. Integrate both sides independently.", domain: "topic0", domainName: "Mathematics", category: "concept", topics: ["Differential Equations"] },
  { id: 9, front: "For the ODE ay'' + by' + cy = 0, what does the discriminant tell you?", back: "b²-4ac > 0: overdamped (two real roots). = 0: critically damped (repeated root). < 0: underdamped (complex roots, oscillatory).", domain: "topic0", domainName: "Mathematics", category: "concept", topics: ["Differential Equations"] },
  { id: 10, front: "What is the Final Value Theorem?", back: "lim(t→∞) f(t) = lim(s→0) s·F(s) — Finds steady-state value from the Laplace transform without inverting.", domain: "topic0", domainName: "Mathematics", category: "formula", topics: ["Laplace Transforms"] },
  { id: 11, front: "What is the physical meaning of the gradient ∇f?", back: "Points in the direction of steepest increase of scalar field f. Its magnitude equals the rate of increase.", domain: "topic0", domainName: "Mathematics", category: "concept", topics: ["Vector Calculus"] },
  { id: 12, front: "When is the dot product A·B zero?", back: "When vectors A and B are perpendicular (orthogonal). A·B = |A||B|cosθ, and cos(90°) = 0.", domain: "topic0", domainName: "Mathematics", category: "concept", topics: ["Vector Calculus"] },
  { id: 13, front: "What is Newton-Raphson's formula?", back: "x_{n+1} = x_n - f(x_n)/f'(x_n) — Quadratic convergence near simple roots. Needs derivative and good initial guess.", domain: "topic0", domainName: "Mathematics", category: "formula", topics: ["Numerical Methods"] },
  { id: 14, front: "Compare trapezoidal and Simpson's rule accuracy.", back: "Trapezoidal: O(h²). Simpson's 1/3: O(h⁴). Simpson's is much more accurate but requires an even number of intervals.", domain: "topic0", domainName: "Mathematics", category: "comparison", topics: ["Numerical Methods"] },
  { id: 15, front: "What is Euler's method for solving ODEs?", back: "y_{n+1} = y_n + h·f(x_n, y_n) — First-order accurate. Simple but needs small step size.", domain: "topic0", domainName: "Mathematics", category: "formula", topics: ["Numerical Methods"] },
  // ═══════════════════════════════════════════════════════════════
  // TOPIC 1 — Probability & Statistics (20 hand-crafted)
  // ═══════════════════════════════════════════════════════════════
  { id: 16, front: "State the addition rule of probability.", back: "P(A∪B) = P(A) + P(B) - P(A∩B) — Subtract overlap to avoid double-counting.", domain: "topic1", domainName: "Probability & Statistics", category: "formula", topics: ["Probability"] },
  { id: 17, front: "What is Bayes' Theorem?", back: "P(A|B) = P(B|A)·P(A)/P(B) — Updates probability of A given new evidence B.", domain: "topic1", domainName: "Probability & Statistics", category: "formula", topics: ["Probability"] },
  { id: 18, front: "What is the mean and variance of a binomial distribution?", back: "Mean = np, Variance = np(1-p). For n trials with success probability p per trial.", domain: "topic1", domainName: "Probability & Statistics", category: "formula", topics: ["Distributions"] },
  { id: 19, front: "What is the 68-95-99.7 rule?", back: "For a normal distribution: 68% within ±1σ, 95% within ±2σ, 99.7% within ±3σ of the mean.", domain: "topic1", domainName: "Probability & Statistics", category: "concept", topics: ["Distributions"] },
  { id: 20, front: "How do you convert to a standard normal distribution?", back: "Z = (X - μ)/σ — Converts any normal to N(0,1). Then use Z-tables for probabilities.", domain: "topic1", domainName: "Probability & Statistics", category: "formula", topics: ["Distributions"] },
  { id: 21, front: "What is the Poisson distribution used for?", back: "Modeling the number of rare events in a fixed interval (time, area, volume). Mean = variance = λ.", domain: "topic1", domainName: "Probability & Statistics", category: "concept", topics: ["Distributions"] },
  { id: 22, front: "What does R² represent in regression?", back: "The fraction of variance in y explained by x. R² = 0.85 means 85% of variation is captured by the model.", domain: "topic1", domainName: "Probability & Statistics", category: "definition", topics: ["Regression"] },
  { id: 23, front: "How do you linearize y = ae^(bx) for regression?", back: "Take ln of both sides: ln(y) = ln(a) + bx. Plot ln(y) vs. x for a straight line.", domain: "topic1", domainName: "Probability & Statistics", category: "tip", topics: ["Regression"] },
  { id: 24, front: "What is the t-test statistic for a single mean?", back: "t = (x̄ - μ₀)/(s/√n) — Degrees of freedom = n-1. Compare to t-table critical value.", domain: "topic1", domainName: "Probability & Statistics", category: "formula", topics: ["Hypothesis Testing"] },
  { id: 25, front: "What is a Type I error vs. Type II error?", back: "Type I (α): Rejecting a true H₀ (false positive). Type II (β): Failing to reject a false H₀ (false negative).", domain: "topic1", domainName: "Probability & Statistics", category: "comparison", topics: ["Hypothesis Testing"] },
  // ═══════════════════════════════════════════════════════════════
  // TOPIC 2 — Computational Tools (10 hand-crafted)
  // ═══════════════════════════════════════════════════════════════
  { id: 26, front: "What does $A$1 mean in a spreadsheet?", back: "Absolute reference — stays fixed when the formula is copied. $ locks the row and/or column.", domain: "topic2", domainName: "Computational Tools", category: "definition", topics: ["Spreadsheets"] },
  { id: 27, front: "What is Goal Seek in spreadsheets?", back: "A tool that adjusts one input cell to achieve a target output value. Essentially single-variable root-finding.", domain: "topic2", domainName: "Computational Tools", category: "definition", topics: ["Spreadsheets"] },
  { id: 28, front: "What is the difference between verification and validation?", back: "Verification: 'Did we solve the equations right?' (math check). Validation: 'Did we solve the right equations?' (physics check).", domain: "topic2", domainName: "Computational Tools", category: "comparison", topics: ["Modeling"] },
  { id: 29, front: "What does mesh refinement do in FEM?", back: "Finer mesh → more accurate results but higher computational cost. Results should converge as mesh is refined.", domain: "topic2", domainName: "Computational Tools", category: "concept", topics: ["Modeling"] },
  { id: 30, front: "What is the fundamental FEM equation?", back: "[K]{u} = {F} — Stiffness matrix times displacement vector equals force vector.", domain: "topic2", domainName: "Computational Tools", category: "formula", topics: ["Modeling"] },
  // ═══════════════════════════════════════════════════════════════
  // TOPIC 3 — Ethics (10 hand-crafted)
  // ═══════════════════════════════════════════════════════════════
  { id: 31, front: "What is the #1 priority in the NSPE Code of Ethics?", back: "Canon 1: Hold paramount the safety, health, and welfare of the public. Public safety always comes first.", domain: "topic3", domainName: "Ethics", category: "concept", topics: ["Codes of Ethics"] },
  { id: 32, front: "What are the four elements of negligence?", back: "Duty, Breach, Causation, and Damages. All four must be present to establish negligence.", domain: "topic3", domainName: "Ethics", category: "definition", topics: ["Liability"] },
  { id: 33, front: "What is the PE licensure pathway?", back: "ABET-accredited BS → FE exam → 4 years experience → PE exam. Each step is required.", domain: "topic3", domainName: "Ethics", category: "concept", topics: ["Licensure"] },
  { id: 34, front: "What is the industrial exemption?", back: "Engineers working for a company (not offering services to the public) may not need a PE license in some jurisdictions.", domain: "topic3", domainName: "Ethics", category: "definition", topics: ["Licensure"] },
  { id: 35, front: "When can an engineer reveal confidential information?", back: "Only with client/employer consent, or when necessary to protect public safety.", domain: "topic3", domainName: "Ethics", category: "tip", topics: ["Codes of Ethics"] },
  // ═══════════════════════════════════════════════════════════════
  // TOPIC 4 — Engineering Economics (15 hand-crafted)
  // ═══════════════════════════════════════════════════════════════
  { id: 36, front: "What is the compound interest formula?", back: "F = P(1+i)^n — Future value of present amount P at interest rate i for n periods.", domain: "topic4", domainName: "Engineering Economics", category: "formula", topics: ["Time Value of Money"] },
  { id: 37, front: "What is the effective annual interest rate?", back: "i_eff = (1 + r/m)^m - 1 — Converts nominal rate r compounded m times/year to effective annual.", domain: "topic4", domainName: "Engineering Economics", category: "formula", topics: ["Time Value of Money"] },
  { id: 38, front: "When should you use Annual Worth instead of Present Worth analysis?", back: "When alternatives have unequal lives. AW automatically handles different lifespans without finding LCM.", domain: "topic4", domainName: "Engineering Economics", category: "tip", topics: ["Cost Analysis"] },
  { id: 39, front: "What is the Benefit-Cost ratio criterion?", back: "B/C = PW(Benefits)/PW(Costs). Project is justified if B/C ≥ 1.0. Used primarily for public projects.", domain: "topic4", domainName: "Engineering Economics", category: "concept", topics: ["Cost Analysis"] },
  { id: 40, front: "What is straight-line depreciation?", back: "D = (B-S)/n — Equal annual deduction. B = initial cost, S = salvage value, n = life.", domain: "topic4", domainName: "Engineering Economics", category: "formula", topics: ["Depreciation"] },
  { id: 41, front: "How does MACRS differ from other depreciation methods?", back: "MACRS always assumes salvage value = 0, uses half-year convention, and specific recovery periods. It is the US tax standard.", domain: "topic4", domainName: "Engineering Economics", category: "comparison", topics: ["Depreciation"] },
  { id: 42, front: "What is a tax shield?", back: "Tax savings = Depreciation × Tax rate. Depreciation reduces taxable income, creating a real cash benefit.", domain: "topic4", domainName: "Engineering Economics", category: "concept", topics: ["Depreciation"] },
  // ═══════════════════════════════════════════════════════════════
  // TOPIC 5 — Statics (15 hand-crafted)
  // ═══════════════════════════════════════════════════════════════
  { id: 43, front: "What are the 2D equilibrium equations?", back: "ΣFx = 0, ΣFy = 0, ΣM = 0 — Three equations for up to three unknowns.", domain: "topic5", domainName: "Statics", category: "formula", topics: ["Equilibrium"] },
  { id: 44, front: "How many reactions does a pin support provide?", back: "Two reactions: Fx and Fy. A roller provides 1 (perpendicular to surface). A fixed support provides 3 (Fx, Fy, M).", domain: "topic5", domainName: "Statics", category: "concept", topics: ["Equilibrium"] },
  { id: 45, front: "When should you use Method of Sections vs. Method of Joints?", back: "Sections: when you need force in ONE specific member (cut ≤3, use 3 equations). Joints: when finding ALL member forces.", domain: "topic5", domainName: "Statics", category: "comparison", topics: ["Trusses"] },
  { id: 46, front: "How do you identify zero-force members?", back: "At a joint with only two non-collinear members and no external load: both are zero-force. At a joint with three members (two collinear), no load: the non-collinear one is zero-force.", domain: "topic5", domainName: "Statics", category: "tip", topics: ["Trusses"] },
  { id: 47, front: "What is the parallel axis theorem?", back: "I = I_c + Ad² — Transfers moment of inertia from centroidal axis to a parallel axis distance d away.", domain: "topic5", domainName: "Statics", category: "formula", topics: ["Centroids"] },
  { id: 48, front: "What is the belt friction equation?", back: "T₂ = T₁·e^(μβ) — β must be in radians. T₂ = tight side, T₁ = slack side.", domain: "topic5", domainName: "Statics", category: "formula", topics: ["Friction"] },
  { id: 49, front: "What is the moment of inertia of a rectangle bh about its centroid?", back: "I = bh³/12 about the centroidal axis parallel to the base b.", domain: "topic5", domainName: "Statics", category: "formula", topics: ["Centroids"] },
  // ═══════════════════════════════════════════════════════════════
  // TOPIC 6 — Dynamics & Vibrations (20 hand-crafted)
  // ═══════════════════════════════════════════════════════════════
  { id: 50, front: "List the three constant-acceleration kinematic equations.", back: "v = v₀+at, s = s₀+v₀t+½at², v² = v₀²+2a(s-s₀). Know three of five variables to solve for the other two.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "formula", topics: ["Kinematics"] },
  { id: 51, front: "What is normal (centripetal) acceleration?", back: "a_n = v²/ρ — Changes the direction of velocity. Points toward center of curvature. ρ = radius.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "formula", topics: ["Kinematics"] },
  { id: 52, front: "For rolling without slipping, what are the constraints?", back: "v_center = Rω, a_center = Rα. The contact point has zero velocity (it is the instantaneous center).", domain: "topic6", domainName: "Dynamics & Vibrations", category: "concept", topics: ["Kinematics"] },
  { id: 53, front: "What is the mass moment of inertia of a solid cylinder?", back: "I = mr²/2 about the central axis. Same for a thin disk.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "formula", topics: ["Kinetics"] },
  { id: 54, front: "When should you use work-energy vs. impulse-momentum?", back: "Work-energy: know forces and displacements. Impulse-momentum: know forces and time. Choosing correctly saves time.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "comparison", topics: ["Energy Methods"] },
  { id: 55, front: "What is the coefficient of restitution?", back: "e = (v₂'-v₁')/(v₁-v₂). e=1: perfectly elastic. e=0: perfectly plastic (objects stick). 0<e<1: real collision.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "definition", topics: ["Energy Methods"] },
  { id: 56, front: "What is the natural frequency of a spring-mass system?", back: "ω_n = √(k/m) in rad/s. f_n = ω_n/(2π) in Hz. Period T = 2π/ω_n.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "formula", topics: ["Vibrations"] },
  { id: 57, front: "What is the damping ratio and what does it tell you?", back: "ζ = c/c_cr where c_cr = 2√(km). ζ<1: underdamped (oscillates). ζ=1: critically damped. ζ>1: overdamped.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "definition", topics: ["Vibrations"] },
  { id: 58, front: "When does vibration isolation occur?", back: "When ω/ω_n > √2 ≈ 1.414. The transmissibility TR < 1, meaning less force is transmitted to the foundation.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "concept", topics: ["Vibrations"] },
  { id: 59, front: "How do springs in series combine?", back: "1/k_eq = 1/k₁ + 1/k₂ (like resistors in parallel). Same force, deflections add. k_eq is less than the smallest individual k.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "formula", topics: ["Vibrations"] },
  // ═══════════════════════════════════════════════════════════════
  // TOPIC 7 — Mechanics of Materials (20 hand-crafted)
  // ═══════════════════════════════════════════════════════════════
  { id: 60, front: "What is Hooke's Law?", back: "σ = Eε — Stress equals Young's modulus times strain, valid in the elastic (linear) region only.", domain: "topic7", domainName: "Mechanics of Materials", category: "formula", topics: ["Stress-Strain"] },
  { id: 61, front: "How is yield strength defined for most metals?", back: "By the 0.2% offset method: draw a line parallel to the elastic region at ε = 0.002. Where it intersects the curve = σ_y.", domain: "topic7", domainName: "Mechanics of Materials", category: "definition", topics: ["Stress-Strain"] },
  { id: 62, front: "What is the relationship between E, G, and ν?", back: "G = E/[2(1+ν)] — Shear modulus relates to Young's modulus through Poisson's ratio.", domain: "topic7", domainName: "Mechanics of Materials", category: "formula", topics: ["Stress-Strain"] },
  { id: 63, front: "What is the axial deformation formula?", back: "δ = FL/(AE) — For constant cross-section and load. F = force, L = length, A = area, E = modulus.", domain: "topic7", domainName: "Mechanics of Materials", category: "formula", topics: ["Axial Loading"] },
  { id: 64, front: "What is the torsion formula?", back: "τ = Tr/J — T = torque, r = radial distance, J = polar moment of inertia. Max stress at outer surface.", domain: "topic7", domainName: "Mechanics of Materials", category: "formula", topics: ["Torsion"] },
  { id: 65, front: "What is the polar moment of inertia for a solid shaft?", back: "J = πd⁴/32 — For a solid circular shaft of diameter d.", domain: "topic7", domainName: "Mechanics of Materials", category: "formula", topics: ["Torsion"] },
  { id: 66, front: "What is the flexure (bending stress) formula?", back: "σ = Mc/I — M = bending moment, c = distance to extreme fiber, I = area moment of inertia. Max at top/bottom.", domain: "topic7", domainName: "Mechanics of Materials", category: "formula", topics: ["Beams"] },
  { id: 67, front: "Where does maximum transverse shear stress occur in a beam?", back: "At the neutral axis. τ = VQ/(Ib). Shear stress is zero at the top and bottom surfaces.", domain: "topic7", domainName: "Mechanics of Materials", category: "concept", topics: ["Beams"] },
  { id: 68, front: "What is the principal stress formula?", back: "σ₁,₂ = (σx+σy)/2 ± √[((σx-σy)/2)² + τxy²] — Maximum and minimum normal stresses.", domain: "topic7", domainName: "Mechanics of Materials", category: "formula", topics: ["Combined Loading"] },
  { id: 69, front: "What is von Mises stress used for?", back: "Failure criterion for ductile materials: σ_vm = √(σ₁²-σ₁σ₂+σ₂²). Compare to σ_y for safety factor.", domain: "topic7", domainName: "Mechanics of Materials", category: "concept", topics: ["Combined Loading"] },
  { id: 70, front: "What is Euler's buckling load?", back: "P_cr = π²EI/(KL)² — Use minimum I. K depends on end conditions: 0.5 (fixed-fixed) to 2.0 (fixed-free).", domain: "topic7", domainName: "Mechanics of Materials", category: "formula", topics: ["Columns"] },
  { id: 71, front: "When is Euler's formula NOT valid?", back: "When σ_cr = P_cr/A exceeds σ_y — the column fails by yielding, not buckling. Check slenderness ratio.", domain: "topic7", domainName: "Mechanics of Materials", category: "tip", topics: ["Columns"] },
  // ═══════════════════════════════════════════════════════════════
  // TOPIC 8 — Material Science (15 hand-crafted)
  // ═══════════════════════════════════════════════════════════════
  { id: 72, front: "How many atoms per unit cell in BCC, FCC, and HCP?", back: "BCC: 2, FCC: 4, HCP: 6. APF: BCC = 0.68, FCC = HCP = 0.74.", domain: "topic8", domainName: "Material Science", category: "definition", topics: ["Crystal Structures"] },
  { id: 73, front: "What is the eutectoid point on the Fe-C diagram?", back: "727°C, 0.76% C. Austenite transforms to pearlite (lamellar ferrite + cementite). Most tested point.", domain: "topic8", domainName: "Material Science", category: "concept", topics: ["Phase Diagrams"] },
  { id: 74, front: "What does quenching produce in steel?", back: "Martensite — a very hard, brittle BCT phase formed by rapid cooling from austenite. Must temper to restore ductility.", domain: "topic8", domainName: "Material Science", category: "concept", topics: ["Phase Diagrams"] },
  { id: 75, front: "What is the Hall-Petch equation?", back: "σ_y = σ₀ + k/√d — Yield strength increases with decreasing grain size d. Grain refinement strengthens.", domain: "topic8", domainName: "Material Science", category: "formula", topics: ["Strengthening"] },
  { id: 76, front: "What is the primary mechanism of plastic deformation in metals?", back: "Dislocation motion along slip planes. All strengthening mechanisms work by impeding dislocation movement.", domain: "topic8", domainName: "Material Science", category: "concept", topics: ["Crystal Structures"] },
  { id: 77, front: "What metals show a ductile-to-brittle transition?", back: "BCC metals (carbon steel) show DBTT. FCC metals (aluminum, copper, stainless steel) remain ductile at low temps.", domain: "topic8", domainName: "Material Science", category: "comparison", topics: ["Mechanical Properties"] },
  { id: 78, front: "What is the Gibbs Phase Rule?", back: "F = C - P + 2 — F = degrees of freedom, C = number of components, P = number of phases.", domain: "topic8", domainName: "Material Science", category: "formula", topics: ["Phase Diagrams"] },
  // ═══════════════════════════════════════════════════════════════
  // TOPIC 9 — Fluid Mechanics (15 hand-crafted)
  // ═══════════════════════════════════════════════════════════════
  { id: 79, front: "What is the hydrostatic pressure equation?", back: "p = p₀ + ρgh — Pressure increases linearly with depth h. Acts equally in all directions at a point.", domain: "topic9", domainName: "Fluid Mechanics", category: "formula", topics: ["Fluid Statics"] },
  { id: 80, front: "State Archimedes' principle.", back: "F_B = ρ_fluid·g·V_displaced — Buoyant force equals weight of displaced fluid.", domain: "topic9", domainName: "Fluid Mechanics", category: "formula", topics: ["Fluid Statics"] },
  { id: 81, front: "Write Bernoulli's equation.", back: "p/(ρg) + V²/(2g) + z = constant — Along a streamline for steady, incompressible, inviscid flow.", domain: "topic9", domainName: "Fluid Mechanics", category: "formula", topics: ["Fluid Dynamics"] },
  { id: 82, front: "What Reynolds number separates laminar from turbulent pipe flow?", back: "Re < 2300: laminar. Re > 4000: turbulent. 2300-4000: transition.", domain: "topic9", domainName: "Fluid Mechanics", category: "concept", topics: ["Fluid Dynamics"] },
  { id: 83, front: "What is the Darcy-Weisbach equation?", back: "h_f = f(L/D)(V²/2g) — Major head loss due to pipe friction. f from Moody chart or f=64/Re (laminar).", domain: "topic9", domainName: "Fluid Mechanics", category: "formula", topics: ["Pipe Flow"] },
  { id: 84, front: "What are the pump affinity laws for the same pump?", back: "Q ∝ N, H ∝ N², P ∝ N³. Double speed → 2× flow, 4× head, 8× power.", domain: "topic9", domainName: "Fluid Mechanics", category: "formula", topics: ["Turbomachinery"] },
  { id: 85, front: "What is NPSH and why does it matter?", back: "Net Positive Suction Head. NPSH_A must exceed NPSH_R to prevent cavitation (vapor bubble formation and collapse).", domain: "topic9", domainName: "Fluid Mechanics", category: "concept", topics: ["Turbomachinery"] },
  // ═══════════════════════════════════════════════════════════════
  // TOPIC 10 — Thermodynamics (20 hand-crafted)
  // ═══════════════════════════════════════════════════════════════
  { id: 86, front: "What is the First Law for a closed system?", back: "Q - W = ΔU — Heat in minus work out equals change in internal energy.", domain: "topic10", domainName: "Thermodynamics", category: "formula", topics: ["Laws"] },
  { id: 87, front: "What is Carnot efficiency?", back: "η = 1 - T_L/T_H — Maximum possible efficiency. Temperatures MUST be absolute (K or R).", domain: "topic10", domainName: "Thermodynamics", category: "formula", topics: ["Laws"] },
  { id: 88, front: "What is the ideal gas law?", back: "PV = nRT. R_universal = 8.314 kJ/(kmol·K). Specific form: Pv = RT where R = R_u/M.", domain: "topic10", domainName: "Thermodynamics", category: "formula", topics: ["Properties"] },
  { id: 89, front: "What is quality (x) and when is it defined?", back: "x = (v-v_f)/(v_g-v_f) — Mass fraction of vapor. Only defined in the two-phase (wet) region, 0 ≤ x ≤ 1.", domain: "topic10", domainName: "Thermodynamics", category: "definition", topics: ["Properties"] },
  { id: 90, front: "What determines Otto cycle efficiency?", back: "η = 1 - 1/r^(γ-1) — Depends only on compression ratio r. Higher r = higher efficiency.", domain: "topic10", domainName: "Thermodynamics", category: "formula", topics: ["Cycles"] },
  { id: 91, front: "What happens at a throttle valve (expansion valve)?", back: "Isenthalpic: h_in = h_out. Irreversible: entropy increases. NOT isentropic. Common FE exam trap.", domain: "topic10", domainName: "Thermodynamics", category: "concept", topics: ["Cycles"] },
  { id: 92, front: "What is relative humidity?", back: "φ = p_v/p_g — Ratio of actual vapor pressure to saturated vapor pressure at the same temperature.", domain: "topic10", domainName: "Thermodynamics", category: "definition", topics: ["Psychrometrics"] },
  { id: 93, front: "What is the stoichiometric air composition?", back: "For each mole of O₂: 3.76 moles of N₂. Air is approximately 21% O₂ and 79% N₂ by volume.", domain: "topic10", domainName: "Thermodynamics", category: "concept", topics: ["Combustion"] },
  // ═══════════════════════════════════════════════════════════════
  // TOPIC 11 — Heat Transfer (15 hand-crafted)
  // ═══════════════════════════════════════════════════════════════
  { id: 94, front: "What is Fourier's law of conduction?", back: "q = -kA(dT/dx) — Heat flow proportional to temperature gradient. k = thermal conductivity.", domain: "topic11", domainName: "Heat Transfer", category: "formula", topics: ["Conduction"] },
  { id: 95, front: "What is the thermal resistance of a plane wall?", back: "R = L/(kA) — Analogous to electrical resistance. For composite walls, add resistances in series.", domain: "topic11", domainName: "Heat Transfer", category: "formula", topics: ["Conduction"] },
  { id: 96, front: "What is the critical radius of insulation?", back: "r_cr = k/h for a cylinder. Adding insulation when r < r_cr INCREASES heat loss (more surface area).", domain: "topic11", domainName: "Heat Transfer", category: "concept", topics: ["Conduction"] },
  { id: 97, front: "What is Newton's law of cooling?", back: "q = hA(T_s - T_∞) — Convection heat transfer. h = convection coefficient. R_conv = 1/(hA).", domain: "topic11", domainName: "Heat Transfer", category: "formula", topics: ["Convection"] },
  { id: 98, front: "What is the Dittus-Boelter correlation?", back: "Nu = 0.023·Re^0.8·Pr^n — For turbulent pipe flow. n=0.4 for heating, 0.3 for cooling.", domain: "topic11", domainName: "Heat Transfer", category: "formula", topics: ["Convection"] },
  { id: 99, front: "What is the Stefan-Boltzmann law?", back: "E = εσT⁴ — σ = 5.67×10⁻⁸ W/(m²·K⁴). T must be in Kelvin. ε = emissivity (0 to 1).", domain: "topic11", domainName: "Heat Transfer", category: "formula", topics: ["Radiation"] },
  { id: 100, front: "What is Kirchhoff's law of radiation?", back: "α = ε at thermal equilibrium — Absorptivity equals emissivity. Frequently tested on the FE exam.", domain: "topic11", domainName: "Heat Transfer", category: "concept", topics: ["Radiation"] },
  { id: 101, front: "When do you use LMTD vs. ε-NTU for heat exchangers?", back: "LMTD: when all four temperatures are known. ε-NTU: when outlet temps are unknown (design problems).", domain: "topic11", domainName: "Heat Transfer", category: "comparison", topics: ["Heat Exchangers"] },
  // ═══════════════════════════════════════════════════════════════
  // TOPIC 12 — Measurements & Controls (10 hand-crafted)
  // ═══════════════════════════════════════════════════════════════
  { id: 102, front: "What is the difference between accuracy and precision?", back: "Accuracy: closeness to true value. Precision: repeatability. A measurement can be precise but inaccurate.", domain: "topic12", domainName: "Measurements & Controls", category: "comparison", topics: ["Sensors"] },
  { id: 103, front: "What is the closed-loop transfer function?", back: "T(s) = G(s)/[1+G(s)H(s)] — For negative feedback. G = forward path, H = feedback.", domain: "topic12", domainName: "Measurements & Controls", category: "formula", topics: ["Controls"] },
  { id: 104, front: "What does each PID term do?", back: "P: reduces error (leaves offset). I: eliminates steady-state error. D: reduces overshoot and improves stability.", domain: "topic12", domainName: "Measurements & Controls", category: "concept", topics: ["Controls"] },
  { id: 105, front: "What is the Nyquist sampling criterion?", back: "f_s > 2·f_max — Sample at least 2× the highest frequency to avoid aliasing.", domain: "topic12", domainName: "Measurements & Controls", category: "formula", topics: ["Signal Processing"] },
  { id: 106, front: "What is a first-order system time constant?", back: "τ: at t=τ, response reaches 63.2% of final value. At t=5τ, approximately 99% (settled).", domain: "topic12", domainName: "Measurements & Controls", category: "concept", topics: ["Controls"] },
  // ═══════════════════════════════════════════════════════════════
  // TOPIC 13 — Mechanical Design (15 hand-crafted)
  // ═══════════════════════════════════════════════════════════════
  { id: 107, front: "What is the bolt preload equation with external load?", back: "F_b = F_i + CP, where C = k_b/(k_b+k_m). Typically C ≈ 0.2-0.3, so most load is carried by clamping.", domain: "topic13", domainName: "Mechanical Design", category: "formula", topics: ["Fasteners"] },
  { id: 108, front: "What is the bearing life equation for ball bearings?", back: "L₁₀ = (C/P)³ — Life in millions of revolutions. Double the load → life drops by factor of 8.", domain: "topic13", domainName: "Mechanical Design", category: "formula", topics: ["Bearings"] },
  { id: 109, front: "What is the gear speed ratio?", back: "ω₂/ω₁ = N₁/N₂ — Inversely proportional to tooth count. Larger gear rotates slower.", domain: "topic13", domainName: "Mechanical Design", category: "formula", topics: ["Gears"] },
  { id: 110, front: "What is the helical spring rate formula?", back: "k = Gd⁴/(8D³N_a) — Note d⁴: doubling wire diameter increases rate 16×.", domain: "topic13", domainName: "Mechanical Design", category: "formula", topics: ["Springs"] },
  { id: 111, front: "What is the approximate endurance limit for steels?", back: "S_e' ≈ 0.5·S_ut for S_ut < 200 ksi. Must modify with k factors (surface, size, loading, temp, reliability).", domain: "topic13", domainName: "Mechanical Design", category: "formula", topics: ["Fatigue"] },
  { id: 112, front: "What is the Modified Goodman criterion?", back: "σ_a/S_e + σ_m/S_ut = 1/n — Apply K_f to alternating stress only, not mean stress.", domain: "topic13", domainName: "Mechanical Design", category: "formula", topics: ["Fatigue"] },
  { id: 113, front: "Do aluminum alloys have an endurance limit?", back: "No. Non-ferrous metals have no true endurance limit — the S-N curve keeps decreasing. Specify fatigue strength at N cycles.", domain: "topic13", domainName: "Mechanical Design", category: "concept", topics: ["Fatigue"] },
  // ═══════════════════════════════════════════════════════════════
  // TOPIC 14 — Manufacturing (10 hand-crafted)
  // ═══════════════════════════════════════════════════════════════
  { id: 114, front: "What is the Taylor tool life equation?", back: "VT^n = C — Higher cutting speed V → shorter tool life T. n depends on tool material (HSS ≈ 0.1, carbide ≈ 0.3).", domain: "topic14", domainName: "Manufacturing", category: "formula", topics: ["Machining"] },
  { id: 115, front: "What is the difference between hot working and cold working?", back: "Hot: above recrystallization temp, lower forces, no work hardening. Cold: below, higher forces, work hardens, better finish.", domain: "topic14", domainName: "Manufacturing", category: "comparison", topics: ["Forming"] },
  { id: 116, front: "What is the blanking/punching force?", back: "F = S_s × t × L — Shear strength × thickness × cut perimeter.", domain: "topic14", domainName: "Manufacturing", category: "formula", topics: ["Forming"] },
  { id: 117, front: "What is the difference between worst-case and statistical tolerancing?", back: "Worst-case: T = ΣT_i (add directly, guaranteed fit). Statistical: T = √(ΣT_i²) (RSS, tighter, ~99.73% fit).", domain: "topic14", domainName: "Manufacturing", category: "comparison", topics: ["Tolerancing"] },
  { id: 118, front: "What is the heat-affected zone (HAZ) in welding?", back: "The region next to the weld where the base metal's microstructure changed due to heat. May be the weakest zone.", domain: "topic14", domainName: "Manufacturing", category: "definition", topics: ["Forming"] },
  // ═══════════════════════════════════════════════════════════════
  // TOPIC 15 — Engineering Management (10 hand-crafted)
  // ═══════════════════════════════════════════════════════════════
  { id: 119, front: "What is the critical path in project management?", back: "The longest path through the network diagram. Activities with zero slack. Determines minimum project duration.", domain: "topic15", domainName: "Engineering Management", category: "definition", topics: ["Project Management"] },
  { id: 120, front: "How do you calculate slack (float)?", back: "Slack = LS - ES = LF - EF. Activities with zero slack are on the critical path.", domain: "topic15", domainName: "Engineering Management", category: "formula", topics: ["Project Management"] },
  { id: 121, front: "What is the PERT expected time formula?", back: "t_e = (a + 4m + b)/6 — Weighted average of optimistic (a), most likely (m), pessimistic (b).", domain: "topic15", domainName: "Engineering Management", category: "formula", topics: ["Project Management"] },
  { id: 122, front: "What is the difference between Cp and Cpk?", back: "Cp: potential capability (if centered). Cpk: actual capability (accounts for off-center). If Cp high but Cpk low → recenter.", domain: "topic15", domainName: "Engineering Management", category: "comparison", topics: ["Quality"] },
  { id: 123, front: "What is Six Sigma's DPMO target?", back: "3.4 defects per million opportunities. Uses DMAIC: Define, Measure, Analyze, Improve, Control.", domain: "topic15", domainName: "Engineering Management", category: "concept", topics: ["Quality"] },
  { id: 124, front: "What is the Pareto principle?", back: "80/20 rule: roughly 80% of defects come from 20% of causes. Focus on the vital few.", domain: "topic15", domainName: "Engineering Management", category: "concept", topics: ["Quality"] },
  // ═══════════════════════════════════════════════════════════════
  // ADDITIONAL CARDS — Topics 0-15 (fill to 250+ hand-crafted)
  // ═══════════════════════════════════════════════════════════════
  // Mathematics extras
  { id: 125, front: "What is the Laplace transform of e^(-at)?", back: "L{e^(-at)} = 1/(s+a) — Fundamental transform for exponential decay.", domain: "topic0", domainName: "Mathematics", category: "formula", topics: ["Laplace Transforms"] },
  { id: 126, front: "What is L'Hopital's rule?", back: "If lim f(x)/g(x) gives 0/0 or ∞/∞, then the limit equals lim f'(x)/g'(x). Differentiate top and bottom separately.", domain: "topic0", domainName: "Mathematics", category: "concept", topics: ["Calculus"] },
  { id: 127, front: "What is the second derivative test for optimization?", back: "At critical point c: f''(c) > 0 → local minimum. f''(c) < 0 → local maximum. f''(c) = 0 → inconclusive.", domain: "topic0", domainName: "Mathematics", category: "concept", topics: ["Calculus"] },
  { id: 128, front: "How do you compute a 3×3 determinant?", back: "Expand along any row or column using cofactors. Each cofactor = (-1)^(i+j) × minor. Use the 'rule of Sarrus' for speed.", domain: "topic0", domainName: "Mathematics", category: "tip", topics: ["Linear Algebra"] },
  { id: 129, front: "What is the divergence theorem?", back: "∯F·dA = ∭(∇·F)dV — Surface flux equals volume integral of divergence. Used in fluid mechanics conservation equations.", domain: "topic0", domainName: "Mathematics", category: "formula", topics: ["Vector Calculus"] },
  { id: 130, front: "What is Green's Theorem?", back: "∮(Pdx + Qdy) = ∬(∂Q/∂x - ∂P/∂y)dA — Relates 2D line integral to double integral over enclosed region.", domain: "topic0", domainName: "Mathematics", category: "formula", topics: ["Vector Calculus"] },
  { id: 131, front: "What is the bisection method?", back: "Root-finding: if f(a)·f(b) < 0, root between a and b. Check midpoint, halve interval. Always converges, but slow (linear).", domain: "topic0", domainName: "Mathematics", category: "concept", topics: ["Numerical Methods"] },
  { id: 132, front: "What is the difference between exact and inexact ODEs?", back: "Exact: M dx + N dy = 0 with ∂M/∂y = ∂N/∂x. Find potential function F where dF = Mdx + Ndy. Inexact needs integrating factor.", domain: "topic0", domainName: "Mathematics", category: "comparison", topics: ["Differential Equations"] },
  // Probability extras
  { id: 133, front: "What is the exponential distribution used for?", back: "Models time between events in a Poisson process. f(x) = λe^(-λx). Mean = 1/λ. Memoryless property.", domain: "topic1", domainName: "Probability & Statistics", category: "concept", topics: ["Distributions"] },
  { id: 134, front: "What is the Central Limit Theorem?", back: "The sampling distribution of the mean approaches normal as n increases, regardless of the population distribution.", domain: "topic1", domainName: "Probability & Statistics", category: "concept", topics: ["Distributions"] },
  { id: 135, front: "How do you use a Z-table?", back: "Convert X to Z = (X-μ)/σ. Look up Z in the table to find P(Z < z). For P(Z > z), use 1 - P(Z < z).", domain: "topic1", domainName: "Probability & Statistics", category: "tip", topics: ["Distributions"] },
  { id: 136, front: "What is the formula for sample variance?", back: "s² = Σ(X_i - x̄)²/(n-1) — Divide by n-1 (not n) for an unbiased estimate.", domain: "topic1", domainName: "Probability & Statistics", category: "formula", topics: ["Descriptive Statistics"] },
  { id: 137, front: "When do you reject H₀?", back: "When |t| > t_critical (from t-table at significance level α with n-1 df). Or equivalently, when p-value < α.", domain: "topic1", domainName: "Probability & Statistics", category: "concept", topics: ["Hypothesis Testing"] },
  // Computational Tools extras
  { id: 138, front: "What is linear interpolation?", back: "y = y₁ + (x-x₁)(y₂-y₁)/(x₂-x₁) — Estimates a value between two known data points.", domain: "topic2", domainName: "Computational Tools", category: "formula", topics: ["Spreadsheets"] },
  { id: 139, front: "What are common element types in FEM?", back: "1D: beam/truss. 2D: triangle/quad (plane stress/strain). 3D: tetrahedron/hexahedron. Choose based on geometry.", domain: "topic2", domainName: "Computational Tools", category: "concept", topics: ["Modeling"] },
  // Ethics extras
  { id: 140, front: "What is strict liability?", back: "Liability without proof of fault. Applies to manufacturers of defective products — they are liable regardless of negligence.", domain: "topic3", domainName: "Ethics", category: "definition", topics: ["Liability"] },
  { id: 141, front: "What should an engineer do if a project endangers the public?", back: "Report concerns to employer first. If unresolved, escalate — ultimately public safety overrides loyalty to employer.", domain: "topic3", domainName: "Ethics", category: "tip", topics: ["Codes of Ethics"] },
  // Economics extras
  { id: 142, front: "What is the MARR?", back: "Minimum Attractive Rate of Return — the lowest rate of return an organization will accept. Used as discount rate for PW analysis.", domain: "topic4", domainName: "Engineering Economics", category: "definition", topics: ["Cost Analysis"] },
  { id: 143, front: "What is incremental analysis?", back: "Compare mutually exclusive alternatives by analyzing the DIFFERENCE in cash flows. Accept increment if Δ-ROR ≥ MARR.", domain: "topic4", domainName: "Engineering Economics", category: "concept", topics: ["Cost Analysis"] },
  { id: 144, front: "What is the payback period?", back: "Time to recover initial investment. Simple: n = Cost/Annual cash flow. Ignores time value of money — use for quick screening only.", domain: "topic4", domainName: "Engineering Economics", category: "definition", topics: ["Cost Analysis"] },
  { id: 145, front: "What is the capital recovery factor?", back: "A = P·[i(1+i)^n/((1+i)^n-1)] — Converts present amount to equivalent annual payment. (A/P, i, n).", domain: "topic4", domainName: "Engineering Economics", category: "formula", topics: ["Time Value of Money"] },
  // Statics extras
  { id: 146, front: "How do you replace a distributed load with an equivalent force?", back: "Resultant = area under load diagram. Location = centroid of the load shape. Triangle: 1/3 from wider end.", domain: "topic5", domainName: "Statics", category: "concept", topics: ["Equilibrium"] },
  { id: 147, front: "What assumptions apply to ideal trusses?", back: "Frictionless pins at joints, loads only at joints, two-force members (axial only), negligible weight.", domain: "topic5", domainName: "Statics", category: "definition", topics: ["Trusses"] },
  { id: 148, front: "What is the moment of inertia of a circle about its centroid?", back: "I = πr⁴/4 = πd⁴/64 — About any centroidal diameter.", domain: "topic5", domainName: "Statics", category: "formula", topics: ["Centroids"] },
  { id: 149, front: "What is μ_s vs μ_k?", back: "μ_s = static friction coefficient (before sliding). μ_k = kinetic (during sliding). Always μ_s > μ_k.", domain: "topic5", domainName: "Statics", category: "comparison", topics: ["Friction"] },
  // Dynamics extras
  { id: 150, front: "What is the instantaneous center of zero velocity?", back: "The point about which a rigid body appears to rotate at that instant. All velocity vectors are perpendicular to lines from the IC.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "concept", topics: ["Kinematics"] },
  { id: 151, front: "What is the conservation of energy equation for dynamics?", back: "T₁ + V₁ = T₂ + V₂ — Valid when only conservative forces (gravity, springs) do work. T=KE, V=PE.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "formula", topics: ["Energy Methods"] },
  { id: 152, front: "What is the relationship P = Tω?", back: "Power = Torque × Angular velocity. In SI: watts = N·m × rad/s. Essential for rotating machinery analysis.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "formula", topics: ["Energy Methods"] },
  { id: 153, front: "What happens at resonance?", back: "When forcing frequency ω ≈ natural frequency ω_n, amplitude becomes very large. Damping limits but doesn't eliminate the peak.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "concept", topics: ["Vibrations"] },
  { id: 154, front: "What is the damped natural frequency?", back: "ω_d = ω_n√(1-ζ²) — Always less than ω_n. Only applies for underdamped systems (ζ < 1).", domain: "topic6", domainName: "Dynamics & Vibrations", category: "formula", topics: ["Vibrations"] },
  // MoM extras
  { id: 155, front: "What is the relationship dV/dx = -w, dM/dx = V?", back: "Shear is negative derivative of distributed load. Moment is integral of shear. These build V and M diagrams.", domain: "topic7", domainName: "Mechanics of Materials", category: "concept", topics: ["Beams"] },
  { id: 156, front: "Where does maximum moment occur in a beam?", back: "Where V = 0 or changes sign. This is the critical location for bending stress.", domain: "topic7", domainName: "Mechanics of Materials", category: "tip", topics: ["Beams"] },
  { id: 157, front: "What is the Tresca criterion?", back: "Maximum shear stress theory: τ_max ≤ σ_y/2. Conservative for ductile materials. Simpler than von Mises.", domain: "topic7", domainName: "Mechanics of Materials", category: "concept", topics: ["Combined Loading"] },
  { id: 158, front: "How do angles work on Mohr's circle?", back: "Angles on Mohr's circle are DOUBLE the physical angles. A 45° physical rotation = 90° on Mohr's circle.", domain: "topic7", domainName: "Mechanics of Materials", category: "tip", topics: ["Combined Loading"] },
  { id: 159, front: "What is Poisson's ratio?", back: "ν = -ε_lateral/ε_axial. Typically 0.25-0.35 for metals. Relates how a material contracts laterally when stretched.", domain: "topic7", domainName: "Mechanics of Materials", category: "definition", topics: ["Stress-Strain"] },
  // Material Science extras
  { id: 160, front: "What is the Lever Rule?", back: "In a two-phase region: W_α = (C_β - C₀)/(C_β - C_α). Gives weight fraction of each phase based on composition.", domain: "topic8", domainName: "Material Science", category: "formula", topics: ["Phase Diagrams"] },
  { id: 161, front: "What is precipitation hardening?", back: "Strengthening by fine precipitates that block dislocation motion. Example: Al-Cu alloys (2024-T6). Requires solution treatment + aging.", domain: "topic8", domainName: "Material Science", category: "concept", topics: ["Strengthening"] },
  { id: 162, front: "What is the difference between annealing and normalizing?", back: "Both heat above A₃. Annealing: slow furnace cool (softest). Normalizing: air cool (finer pearlite, moderate strength).", domain: "topic8", domainName: "Material Science", category: "comparison", topics: ["Phase Diagrams"] },
  { id: 163, front: "What is galvanic corrosion?", back: "When two dissimilar metals are in electrical contact with an electrolyte. The more anodic (active) metal corrodes preferentially.", domain: "topic8", domainName: "Material Science", category: "concept", topics: ["Corrosion"] },
  // Fluid Mechanics extras
  { id: 164, front: "What is the continuity equation?", back: "A₁V₁ = A₂V₂ for steady, incompressible flow. Conservation of mass: what goes in must come out.", domain: "topic9", domainName: "Fluid Mechanics", category: "formula", topics: ["Fluid Dynamics"] },
  { id: 165, front: "What is the friction factor for laminar pipe flow?", back: "f = 64/Re — No Moody chart needed. For turbulent flow, use the Moody chart with Re and ε/D.", domain: "topic9", domainName: "Fluid Mechanics", category: "formula", topics: ["Pipe Flow"] },
  { id: 166, front: "What is the exit loss coefficient?", back: "K = 1.0 for a pipe discharging into a large tank. Sharp entrance K = 0.5. These are standard minor loss values.", domain: "topic9", domainName: "Fluid Mechanics", category: "concept", topics: ["Pipe Flow"] },
  { id: 167, front: "What is specific speed used for?", back: "N_s classifies pump type: low N_s = radial (centrifugal), medium = mixed flow, high = axial. Helps select pump configuration.", domain: "topic9", domainName: "Fluid Mechanics", category: "concept", topics: ["Turbomachinery"] },
  { id: 168, front: "What causes boundary layer transition?", back: "Laminar → turbulent at Re_x ≈ 5×10⁵ on a flat plate. Turbulent BL has higher skin friction but resists separation better.", domain: "topic9", domainName: "Fluid Mechanics", category: "concept", topics: ["External Flow"] },
  // Thermodynamics extras
  { id: 169, front: "What is the difference between c_p and c_v?", back: "c_p: specific heat at constant pressure. c_v: at constant volume. c_p - c_v = R. γ = c_p/c_v.", domain: "topic10", domainName: "Thermodynamics", category: "comparison", topics: ["Properties"] },
  { id: 170, front: "What are the four processes in the Rankine cycle?", back: "1→2: Pump (isentropic). 2→3: Boiler (constant P). 3→4: Turbine (isentropic). 4→1: Condenser (constant P).", domain: "topic10", domainName: "Thermodynamics", category: "concept", topics: ["Cycles"] },
  { id: 171, front: "What is the Brayton cycle used for?", back: "Gas turbines and jet engines. Efficiency: η = 1 - 1/r_p^((γ-1)/γ). Depends only on pressure ratio.", domain: "topic10", domainName: "Thermodynamics", category: "concept", topics: ["Cycles"] },
  { id: 172, front: "What is the COP relationship for heat pumps?", back: "COP_HP = COP_R + 1. Heat pump COP is always at least 1 greater than refrigerator COP.", domain: "topic10", domainName: "Thermodynamics", category: "formula", topics: ["Cycles"] },
  { id: 173, front: "What is the dew point temperature?", back: "Temperature at which air becomes saturated (φ = 100%) if cooled at constant pressure and humidity ratio.", domain: "topic10", domainName: "Thermodynamics", category: "definition", topics: ["Psychrometrics"] },
  { id: 174, front: "What is the equivalence ratio Φ?", back: "Φ = AF_stoich/AF_actual. Φ < 1: lean (excess air). Φ = 1: stoichiometric. Φ > 1: rich (excess fuel).", domain: "topic10", domainName: "Thermodynamics", category: "definition", topics: ["Combustion"] },
  // Heat Transfer extras
  { id: 175, front: "What is the thermal-electrical analogy?", back: "q ↔ I (current), ΔT ↔ V (voltage), R_thermal ↔ R_electrical. Series resistances add. q = ΔT/R.", domain: "topic11", domainName: "Heat Transfer", category: "concept", topics: ["Conduction"] },
  { id: 176, front: "What is the Nusselt number?", back: "Nu = hL/k_fluid. Dimensionless convection coefficient. Links empirical correlations to the heat transfer coefficient h.", domain: "topic11", domainName: "Heat Transfer", category: "definition", topics: ["Convection"] },
  { id: 177, front: "What is the Rayleigh number?", back: "Ra = Gr·Pr = gβΔTL³/(να). Parameter for natural convection correlations. Higher Ra → stronger buoyancy-driven flow.", domain: "topic11", domainName: "Heat Transfer", category: "formula", topics: ["Convection"] },
  { id: 178, front: "Why must radiation temperatures be absolute?", back: "Stefan-Boltzmann law uses T⁴. The formula E = εσT⁴ requires Kelvin or Rankine. Using °C or °F gives wrong answers.", domain: "topic11", domainName: "Heat Transfer", category: "tip", topics: ["Radiation"] },
  { id: 179, front: "What is the LMTD formula?", back: "ΔT_lm = (ΔT₁-ΔT₂)/ln(ΔT₁/ΔT₂). For counterflow: ΔT₁ = T_h,in-T_c,out; ΔT₂ = T_h,out-T_c,in.", domain: "topic11", domainName: "Heat Transfer", category: "formula", topics: ["Heat Exchangers"] },
  // Controls extras
  { id: 180, front: "What is the strain gauge factor?", back: "GF (gauge factor) ≈ 2 for metal foil gauges. ΔR/R = GF·ε. Connects resistance change to strain.", domain: "topic12", domainName: "Measurements & Controls", category: "formula", topics: ["Sensors"] },
  { id: 181, front: "How does a thermocouple work?", back: "Seebeck effect: voltage generated at junction of two different metals proportional to temperature difference.", domain: "topic12", domainName: "Measurements & Controls", category: "concept", topics: ["Sensors"] },
  { id: 182, front: "What is the 2% settling time?", back: "t_s ≈ 4/(ζω_n) — Time for a second-order system step response to stay within 2% of the final value.", domain: "topic12", domainName: "Measurements & Controls", category: "formula", topics: ["Controls"] },
  // Mechanical Design extras
  { id: 183, front: "What meshing requirement must gears satisfy?", back: "Two meshing gears must have the SAME diametral pitch (or module) and the same pressure angle.", domain: "topic13", domainName: "Mechanical Design", category: "concept", topics: ["Gears"] },
  { id: 184, front: "What is the radial force in a spur gear mesh?", back: "W_r = W_t·tan(φ). φ = pressure angle (typically 20°). This is the separating force between gears.", domain: "topic13", domainName: "Mechanical Design", category: "formula", topics: ["Gears"] },
  { id: 185, front: "What is the spring index C?", back: "C = D/d (mean coil diameter / wire diameter). Typical range 4-12. Too small → hard to manufacture. Too large → tangling.", domain: "topic13", domainName: "Mechanical Design", category: "definition", topics: ["Springs"] },
  { id: 186, front: "What is K_f in fatigue analysis?", back: "Fatigue stress concentration factor: K_f = 1 + q(K_t - 1). q = notch sensitivity. Apply to ALTERNATING stress only.", domain: "topic13", domainName: "Mechanical Design", category: "formula", topics: ["Fatigue"] },
  { id: 187, front: "What is the critical speed of a shaft?", back: "The speed at which resonance occurs with lateral vibration. Design: operate < 0.7·ω_cr or > 1.3·ω_cr.", domain: "topic13", domainName: "Mechanical Design", category: "concept", topics: ["Shafts"] },
  // Manufacturing extras
  { id: 188, front: "What is MRR in turning?", back: "Material Removal Rate = V·f·d. V = cutting speed (πDN), f = feed, d = depth of cut.", domain: "topic14", domainName: "Manufacturing", category: "formula", topics: ["Machining"] },
  { id: 189, front: "What is the difference between blanking and punching?", back: "Blanking: the punched-out piece IS the product. Punching: the remaining sheet IS the product (the hole matters).", domain: "topic14", domainName: "Manufacturing", category: "comparison", topics: ["Forming"] },
  { id: 190, front: "What is the recrystallization temperature?", back: "≈ 0.3-0.5 × T_melt (in K). Hot working is above this temp (no work hardening). Cold working is below.", domain: "topic14", domainName: "Manufacturing", category: "concept", topics: ["Forming"] },
  // Management extras
  { id: 191, front: "What are the seven basic quality tools?", back: "Cause-effect diagram, check sheet, control chart, histogram, Pareto chart, scatter diagram, flowchart.", domain: "topic15", domainName: "Engineering Management", category: "definition", topics: ["Quality"] },
  { id: 192, front: "What does DMAIC stand for?", back: "Define, Measure, Analyze, Improve, Control — the Six Sigma improvement methodology.", domain: "topic15", domainName: "Engineering Management", category: "definition", topics: ["Quality"] },
  { id: 193, front: "What indicates a process is out of control?", back: "Point beyond control limits, 7+ consecutive points on one side of center, or systematic patterns (trends, cycles).", domain: "topic15", domainName: "Engineering Management", category: "concept", topics: ["Quality"] },
  // ═══════════════════════════════════════════════════════════════
  // BATCH 3 — Additional depth cards to reach 600+ total
  // ═══════════════════════════════════════════════════════════════
  { id: 194, front: "What is the arc length formula?", back: "L = ∫√(1+[f'(x)]²) dx — Length of curve y=f(x) from a to b.", domain: "topic0", domainName: "Mathematics", category: "formula", topics: ["Calculus"] },
  { id: 195, front: "What is a partial derivative?", back: "∂f/∂x: differentiate f(x,y) with respect to x while treating y as a constant. Used for multivariable functions.", domain: "topic0", domainName: "Mathematics", category: "definition", topics: ["Calculus"] },
  { id: 196, front: "What is the trace of a matrix?", back: "Sum of diagonal elements. For 2×2 [[a,b],[c,d]]: trace = a+d. Sum of eigenvalues = trace.", domain: "topic0", domainName: "Mathematics", category: "definition", topics: ["Linear Algebra"] },
  { id: 197, front: "What is the half-life formula?", back: "t₁/₂ = ln(2)/|k| — Time for quantity to halve in exponential decay y = y₀e^(kt), k < 0.", domain: "topic0", domainName: "Mathematics", category: "formula", topics: ["Differential Equations"] },
  { id: 198, front: "What is the cross product used for?", back: "Finds a vector perpendicular to both inputs. |A×B| = |A||B|sinθ = area of parallelogram. Zero for parallel vectors.", domain: "topic0", domainName: "Mathematics", category: "concept", topics: ["Vector Calculus"] },
  { id: 199, front: "What is fixed-point iteration?", back: "Rewrite f(x)=0 as x=g(x), iterate x_{n+1} = g(x_n). Converges if |g'(x)| < 1 near the fixed point.", domain: "topic0", domainName: "Mathematics", category: "concept", topics: ["Numerical Methods"] },
  { id: 200, front: "What is the mean and variance of a Poisson distribution?", back: "Both equal λ. Mean = λ, Variance = λ. This is a unique property of the Poisson distribution.", domain: "topic1", domainName: "Probability & Statistics", category: "formula", topics: ["Distributions"] },
  { id: 201, front: "What is the complement rule?", back: "P(A') = 1 - P(A). Often easier to calculate P(not A) and subtract from 1.", domain: "topic1", domainName: "Probability & Statistics", category: "formula", topics: ["Probability"] },
  { id: 202, front: "What is conditional probability?", back: "P(A|B) = P(A∩B)/P(B). Probability of A given that B has occurred.", domain: "topic1", domainName: "Probability & Statistics", category: "formula", topics: ["Probability"] },
  { id: 203, front: "What does a confidence interval tell you?", back: "A 95% CI means: if we repeated the experiment many times, 95% of intervals would contain the true parameter.", domain: "topic1", domainName: "Probability & Statistics", category: "concept", topics: ["Hypothesis Testing"] },
  { id: 204, front: "What is the power of a test?", back: "Power = 1 - β = probability of correctly rejecting a false H₀. Higher power → better at detecting real effects.", domain: "topic1", domainName: "Probability & Statistics", category: "definition", topics: ["Hypothesis Testing"] },
  { id: 205, front: "What is a mixed cell reference?", back: "$A1: column locked, row adjusts. A$1: row locked, column adjusts. Useful when copying across or down.", domain: "topic2", domainName: "Computational Tools", category: "definition", topics: ["Spreadsheets"] },
  { id: 206, front: "What are boundary conditions in FEM?", back: "Prescribed displacements (Dirichlet) or forces (Neumann) at mesh boundaries. Essential for a unique solution.", domain: "topic2", domainName: "Computational Tools", category: "concept", topics: ["Modeling"] },
  { id: 207, front: "Can an engineer accept gifts from a client?", back: "Only if it does not create a conflict of interest and is disclosed. Substantial gifts that could influence judgment are prohibited.", domain: "topic3", domainName: "Ethics", category: "concept", topics: ["Codes of Ethics"] },
  { id: 208, front: "What is the standard of care?", back: "The level of skill and diligence a reasonably competent engineer would exercise under similar circumstances.", domain: "topic3", domainName: "Ethics", category: "definition", topics: ["Liability"] },
  { id: 209, front: "What is an arithmetic gradient in TVM?", back: "Cash flow that increases by a constant amount G each period. P_G = G·[((1+i)^n-in-1)/(i²(1+i)^n)].", domain: "topic4", domainName: "Engineering Economics", category: "formula", topics: ["Time Value of Money"] },
  { id: 210, front: "What is the rate of return method?", back: "Find interest rate i* that makes PW = 0. If i* ≥ MARR, the investment is justified.", domain: "topic4", domainName: "Engineering Economics", category: "concept", topics: ["Cost Analysis"] },
  { id: 211, front: "What is double declining balance depreciation?", back: "D_k = (2/n)·BV_{k-1}. Rate = 2/n. Never depreciate below salvage value. Switch to SL when SL gives more.", domain: "topic4", domainName: "Engineering Economics", category: "formula", topics: ["Depreciation"] },
  { id: 212, front: "What is the breakeven formula?", back: "Q_BE = Fixed costs/(Price - Variable cost per unit). Volume at which revenue equals total costs.", domain: "topic4", domainName: "Engineering Economics", category: "formula", topics: ["Cost Analysis"] },
  { id: 213, front: "How do you determine if a structure is statically determinate?", back: "Count unknowns vs. equilibrium equations. 2D: 3 equations. If unknowns = 3 → determinate. More → indeterminate.", domain: "topic5", domainName: "Statics", category: "concept", topics: ["Equilibrium"] },
  { id: 214, front: "What is the centroid of a triangle from its base?", back: "h/3 from the base, where h is the triangle height. Area = bh/2.", domain: "topic5", domainName: "Statics", category: "formula", topics: ["Centroids"] },
  { id: 215, front: "What is a couple?", back: "Two equal, opposite, non-collinear forces. Creates a pure moment M = F·d. Effect is the same regardless of location.", domain: "topic5", domainName: "Statics", category: "definition", topics: ["Equilibrium"] },
  { id: 216, front: "What is the angular equivalent of v = v₀ + at?", back: "ω = ω₀ + αt — Angular velocity under constant angular acceleration.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "formula", topics: ["Kinematics"] },
  { id: 217, front: "What is the parallel axis theorem for mass moment of inertia?", back: "I_O = I_G + md² — Same form as area version, but uses mass instead of area.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "formula", topics: ["Kinetics"] },
  { id: 218, front: "What is the total KE of a rolling body?", back: "T = ½mv_G² + ½I_Gω². For rolling without slip: T = ½(I_G + mR²)ω².", domain: "topic6", domainName: "Dynamics & Vibrations", category: "formula", topics: ["Rigid Body"] },
  { id: 219, front: "What is angular momentum?", back: "H = Iω. Newton's rotational law: ΣM = dH/dt. Conserved when no external torques.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "formula", topics: ["Kinetics"] },
  { id: 220, front: "What is the section modulus S?", back: "S = I/c — Moment of inertia divided by distance to extreme fiber. σ_max = M/S. Useful for beam design.", domain: "topic7", domainName: "Mechanics of Materials", category: "definition", topics: ["Beams"] },
  { id: 221, front: "What is the angle of twist for a shaft?", back: "φ = TL/(GJ) — In radians. T=torque, L=length, G=shear modulus, J=polar moment.", domain: "topic7", domainName: "Mechanics of Materials", category: "formula", topics: ["Torsion"] },
  { id: 222, front: "How do you solve statically indeterminate axial problems?", back: "Write equilibrium + compatibility (deformation) + force-deformation (δ=FL/AE) equations. Solve the system.", domain: "topic7", domainName: "Mechanics of Materials", category: "tip", topics: ["Axial Loading"] },
  { id: 223, front: "What is 1 horsepower in ft-lb/s?", back: "1 hp = 550 ft·lb/s. In SI: 1 hp ≈ 745.7 W. Essential for power-torque conversions.", domain: "topic7", domainName: "Mechanics of Materials", category: "formula", topics: ["Torsion"] },
  { id: 224, front: "What is the difference between toughness and resilience?", back: "Toughness: total area under σ-ε curve (total energy to fracture). Resilience: area under elastic portion only.", domain: "topic8", domainName: "Material Science", category: "comparison", topics: ["Mechanical Properties"] },
  { id: 225, front: "What is true stress and true strain?", back: "σ_true = σ_eng(1+ε_eng). ε_true = ln(1+ε_eng). Account for changing cross-section during tensile test.", domain: "topic8", domainName: "Material Science", category: "formula", topics: ["Mechanical Properties"] },
  { id: 226, front: "What is the modulus of resilience?", back: "U_r = σ_y²/(2E) — Maximum elastic energy per unit volume. Area of triangle under elastic stress-strain curve.", domain: "topic8", domainName: "Material Science", category: "formula", topics: ["Mechanical Properties"] },
  { id: 227, front: "What is the center of pressure?", back: "y_R = y_c + I_xc/(y_c·A). Where the resultant hydrostatic force acts. Always below the centroid.", domain: "topic9", domainName: "Fluid Mechanics", category: "formula", topics: ["Fluid Statics"] },
  { id: 228, front: "What is the drag force equation?", back: "F_D = C_D·½ρV²·A. C_D from tables/charts; A = reference area (usually frontal for bluff bodies).", domain: "topic9", domainName: "Fluid Mechanics", category: "formula", topics: ["External Flow"] },
  { id: 229, front: "What are the assumptions for Bernoulli's equation?", back: "Steady flow, incompressible, inviscid (no friction), along a streamline. Violating any requires the general energy equation.", domain: "topic9", domainName: "Fluid Mechanics", category: "concept", topics: ["Fluid Dynamics"] },
  { id: 230, front: "What is the Kelvin-Planck statement?", back: "No heat engine can convert ALL heat to work — there must be some heat rejection. Sets theoretical limits.", domain: "topic10", domainName: "Thermodynamics", category: "concept", topics: ["Laws"] },
  { id: 231, front: "What is an isentropic process?", back: "Reversible + adiabatic. Entropy constant (s₁ = s₂). For ideal gas: PV^γ = const and T₂/T₁ = (P₂/P₁)^((γ-1)/γ).", domain: "topic10", domainName: "Thermodynamics", category: "definition", topics: ["Properties"] },
  { id: 232, front: "How do you determine the state of water/steam?", back: "Compare T to T_sat at given P (or P to P_sat at given T). Below = subcooled liquid. Above = superheated vapor. At = two-phase.", domain: "topic10", domainName: "Thermodynamics", category: "tip", topics: ["Properties"] },
  { id: 233, front: "What is the overall heat transfer coefficient U?", back: "1/U = 1/h_i + R_wall + 1/h_o. Combines convection on both sides and wall conduction into one coefficient.", domain: "topic11", domainName: "Heat Transfer", category: "formula", topics: ["Heat Exchangers"] },
  { id: 234, front: "What is the NTU in heat exchanger analysis?", back: "NTU = UA/C_min. Number of Transfer Units. Higher NTU → higher effectiveness. C = ṁc_p.", domain: "topic11", domainName: "Heat Transfer", category: "definition", topics: ["Heat Exchangers"] },
  { id: 235, front: "What is the view factor summation rule?", back: "ΣF_ij = 1 for all j in an enclosure. All radiation leaving surface i must reach some surface.", domain: "topic11", domainName: "Heat Transfer", category: "formula", topics: ["Radiation"] },
  { id: 236, front: "What is a Wheatstone bridge used for?", back: "Measures small resistance changes (strain gauges). Balanced when R₁R₃ = R₂R₄. Output voltage proportional to strain.", domain: "topic12", domainName: "Measurements & Controls", category: "concept", topics: ["Sensors"] },
  { id: 237, front: "What is the ADC resolution formula?", back: "Resolution = Full Scale Range / 2^n. n = number of bits. More bits = finer resolution.", domain: "topic12", domainName: "Measurements & Controls", category: "formula", topics: ["Signal Processing"] },
  { id: 238, front: "What is aliasing?", back: "When sampling rate < 2·f_max, high-frequency signals appear as low-frequency artifacts. Prevented by the Nyquist criterion.", domain: "topic12", domainName: "Measurements & Controls", category: "definition", topics: ["Signal Processing"] },
  { id: 239, front: "What SAE Grade 8 bolt properties?", back: "Proof strength: 120 ksi. Tensile strength: 150 ksi. Highest common grade. Marked with 6 radial lines on head.", domain: "topic13", domainName: "Mechanical Design", category: "concept", topics: ["Fasteners"] },
  { id: 240, front: "How does doubling load affect ball bearing life?", back: "L₁₀ = (C/P)³. Double P → (C/2P)³ = (1/8)·(C/P)³. Life drops by factor of 8.", domain: "topic13", domainName: "Mechanical Design", category: "concept", topics: ["Bearings"] },
  { id: 241, front: "What does an idler gear do?", back: "Changes rotation direction but does NOT affect the speed ratio. Useful for direction control in gear trains.", domain: "topic13", domainName: "Mechanical Design", category: "concept", topics: ["Gears"] },
  { id: 242, front: "What is the Soderberg criterion?", back: "σ_a/S_e + σ_m/S_y = 1/n. More conservative than Goodman (uses S_y instead of S_ut for mean stress).", domain: "topic13", domainName: "Mechanical Design", category: "formula", topics: ["Fatigue"] },
  { id: 243, front: "What tool materials are ranked from toughest to hardest?", back: "HSS (toughest) → Carbide → Ceramic → CBN → Diamond (hardest). Higher hardness = higher cutting speed capability.", domain: "topic14", domainName: "Manufacturing", category: "comparison", topics: ["Machining"] },
  { id: 244, front: "What is the difference between SMAW, GMAW, and GTAW?", back: "SMAW (stick): manual, versatile. GMAW (MIG): wire-fed, high production. GTAW (TIG): tungsten, high quality for thin sections.", domain: "topic14", domainName: "Manufacturing", category: "comparison", topics: ["Forming"] },
  { id: 245, front: "What is a clearance fit?", back: "Shaft maximum size is always less than hole minimum size. Always a positive gap between parts.", domain: "topic14", domainName: "Manufacturing", category: "definition", topics: ["Tolerancing"] },
  { id: 246, front: "What is the Gantt chart?", back: "Horizontal bar chart showing task schedule. Easy to read timeline but doesn't clearly show dependencies like network diagrams.", domain: "topic15", domainName: "Engineering Management", category: "definition", topics: ["Project Management"] },
  { id: 247, front: "What is the PERT variance formula?", back: "σ² = ((b-a)/6)² for a single activity. Project variance = sum of critical path activity variances.", domain: "topic15", domainName: "Engineering Management", category: "formula", topics: ["Project Management"] },
  { id: 248, front: "What Cpk value indicates a capable process?", back: "Cpk ≥ 1.33 is considered capable. Cpk < 1.0 means excessive defects. Six Sigma targets Cpk ≈ 2.0.", domain: "topic15", domainName: "Engineering Management", category: "concept", topics: ["Quality"] },
  { id: 249, front: "What is the forward pass in CPM?", back: "Calculate ES (earliest start) and EF (earliest finish) left to right. EF = ES + Duration. ES of successor = max(EF of predecessors).", domain: "topic15", domainName: "Engineering Management", category: "concept", topics: ["Project Management"] },
  { id: 250, front: "What is the backward pass in CPM?", back: "Calculate LF (latest finish) and LS (latest start) right to left. LS = LF - Duration. LF of predecessor = min(LS of successors).", domain: "topic15", domainName: "Engineering Management", category: "concept", topics: ["Project Management"] },

  // ═══════════════════════════════════════════════════════════════
  // EXAM TRAPS, DEEP COMPARISONS & WORKED EXAMPLES (130 cards)
  // ═══════════════════════════════════════════════════════════════

  // --- MATH EXAM TRAPS ---
  { id: 251, front: "⚠️ EXAM TRAP: When using L'Hôpital's rule, what must you verify first?", back: "The limit must be an indeterminate form (0/0 or ∞/∞). Applying L'Hôpital to a non-indeterminate form gives the WRONG answer. Always check the form before differentiating.", domain: "topic0", domainName: "Mathematics", category: "tip", topics: ["Calculus"] },
  { id: 252, front: "⚠️ EXAM TRAP: What's the common mistake with the chain rule?", back: "Forgetting the inner derivative. d/dx[sin(3x)] = cos(3x)·3, NOT just cos(3x). Always multiply by the derivative of the inner function.", domain: "topic0", domainName: "Mathematics", category: "tip", topics: ["Calculus"] },
  { id: 253, front: "⚠️ EXAM TRAP: Eigenvalue problem — what equation do you solve?", back: "det(A - λI) = 0, NOT det(A - λ) = 0. You subtract λ from EACH diagonal element, not from the whole matrix.", domain: "topic0", domainName: "Mathematics", category: "tip", topics: ["Linear Algebra"] },
  { id: 254, front: "WORKED EXAMPLE: Find roots of y'' + 4y' + 3y = 0", back: "Characteristic eq: r² + 4r + 3 = 0 → (r+1)(r+3) = 0 → r = -1, -3. Solution: y = C₁e^(-x) + C₂e^(-3x). Real, distinct roots → two exponentials.", domain: "topic0", domainName: "Mathematics", category: "concept", topics: ["Differential Equations"] },
  { id: 255, front: "Compare: Newton-Raphson vs. Bisection method", back: "Newton-Raphson: quadratic convergence (fast) but needs f'(x) and good initial guess — can diverge. Bisection: linear convergence (slow) but ALWAYS converges if f(a)f(b) < 0. Use bisection for reliability, Newton for speed.", domain: "topic0", domainName: "Mathematics", category: "comparison", topics: ["Numerical Methods"] },

  // --- PROB/STATS TRAPS ---
  { id: 256, front: "⚠️ EXAM TRAP: Confidence interval interpretation — what does 95% CI NOT mean?", back: "It does NOT mean 'there is a 95% probability the true mean is in this interval.' It means: if we repeated the experiment many times, 95% of such intervals would contain the true mean. The specific interval either contains μ or it doesn't.", domain: "topic1", domainName: "Probability & Statistics", category: "tip", topics: ["Hypothesis Testing"] },
  { id: 257, front: "⚠️ EXAM TRAP: When to use t-test vs z-test?", back: "t-test: σ unknown AND small sample (n < 30). z-test: σ known OR large sample (n ≥ 30, by CLT). FE exam often gives s (sample std dev) → t-test. If they give σ (population) → z-test.", domain: "topic1", domainName: "Probability & Statistics", category: "tip", topics: ["Hypothesis Testing"] },
  { id: 258, front: "Compare: Binomial vs. Poisson vs. Normal distributions", back: "Binomial: fixed n trials, yes/no outcome, P(X=k) = C(n,k)p^k(1-p)^(n-k). Poisson: rare events, no fixed n, P(X=k) = e^(-λ)λ^k/k!. Normal: continuous, symmetric bell curve. Poisson ≈ Binomial when n large, p small.", domain: "topic1", domainName: "Probability & Statistics", category: "comparison", topics: ["Distributions"] },
  { id: 259, front: "WORKED EXAMPLE: Series vs parallel reliability", back: "Series: R_sys = R₁·R₂ (both must work). Two 0.9 components: 0.9×0.9 = 0.81. Parallel: R_sys = 1-(1-R₁)(1-R₂) (at least one works). Same: 1-0.1×0.1 = 0.99. Parallel dramatically improves reliability.", domain: "topic1", domainName: "Probability & Statistics", category: "concept", topics: ["Reliability"] },

  // --- ECONOMICS TRAPS ---
  { id: 260, front: "⚠️ EXAM TRAP: IRR vs NPV for mutually exclusive alternatives", back: "NEVER compare IRR directly between mutually exclusive alternatives. Use incremental IRR or just compare NPVs. A smaller project with higher IRR may add less value than a larger project with lower IRR.", domain: "topic4", domainName: "Engineering Economics", category: "tip", topics: ["Cost Analysis"] },
  { id: 261, front: "⚠️ EXAM TRAP: Sunk costs in economic analysis", back: "NEVER include sunk costs in economic analysis. A sunk cost is money already spent that cannot be recovered. Only future costs and benefits matter. If the FE exam mentions 'money already spent,' it's testing whether you exclude it.", domain: "topic4", domainName: "Engineering Economics", category: "tip", topics: ["Cost Analysis"] },
  { id: 262, front: "WORKED EXAMPLE: Effective interest rate", back: "12% compounded monthly: i_eff = (1 + 0.12/12)^12 - 1 = (1.01)^12 - 1 = 12.68%. Key: effective rate > nominal rate when compounding more than once per year.", domain: "topic4", domainName: "Engineering Economics", category: "concept", topics: ["Time Value of Money"] },
  { id: 263, front: "Compare: NPV vs. IRR vs. Payback period", back: "NPV: accounts for time value, gives dollar value added — BEST method. IRR: rate making NPV=0, good for communication, misleading for mutually exclusive. Payback: ignores TVM, quick screening only.", domain: "topic4", domainName: "Engineering Economics", category: "comparison", topics: ["Cost Analysis"] },

  // --- STATICS TRAPS ---
  { id: 264, front: "⚠️ EXAM TRAP: Moment arm in moment calculations", back: "The moment arm is the PERPENDICULAR distance from the point to the force's LINE OF ACTION, not the distance to where the force is applied. M = F × d_perp. Drawing the FBD correctly prevents this error.", domain: "topic5", domainName: "Statics", category: "tip", topics: ["Equilibrium"] },
  { id: 265, front: "⚠️ EXAM TRAP: Triangular distributed load resultant location", back: "Resultant of a triangular load acts at 1/3 from the HEAVY end (2/3 from the light end). Common mistake: placing it at 1/3 from the wrong end. Draw the triangle and find its centroid.", domain: "topic5", domainName: "Statics", category: "tip", topics: ["Equilibrium"] },
  { id: 266, front: "Compare: Method of Joints vs. Method of Sections — when to use each", back: "Joints: start at a joint with ≤2 unknowns, solve ΣFx=ΣFy=0. Best when finding ALL forces. Sections: cut truss, pick side with fewer unknowns, use 3 equilibrium eqs. Best when finding ONE specific member.", domain: "topic5", domainName: "Statics", category: "comparison", topics: ["Trusses"] },
  { id: 267, front: "WORKED EXAMPLE: Composite centroid", back: "L-shape: 200×20mm horizontal + 20×180mm vertical. A₁=4000, ȳ₁=10. A₂=3600, ȳ₂=110. ȳ = (4000×10+3600×110)/(4000+3600) = 436000/7600 = 57.4mm from bottom.", domain: "topic5", domainName: "Statics", category: "concept", topics: ["Centroids"] },

  // --- DYNAMICS TRAPS ---
  { id: 268, front: "⚠️ EXAM TRAP: rpm to rad/s conversion", back: "ω = N × 2π/60, NOT N × π/30 (they're the same, but double-check!). 1000 rpm = 1000×2π/60 = 104.7 rad/s. Common error: forgetting the 2π or the /60.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "tip", topics: ["Kinematics"] },
  { id: 269, front: "⚠️ EXAM TRAP: Impulse-momentum — sign convention for rebounding objects", back: "If a ball hits a wall at -10 m/s and rebounds at +8 m/s, impulse = m(v₂-v₁) = m(8-(-10)) = 18m. The velocity CHANGES SIGN. Most common error: using |8-10| = 2m instead of 18m.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "tip", topics: ["Kinetics"] },
  { id: 270, front: "Compare: Conservation of energy vs. impulse-momentum", back: "Energy: use when you know positions/heights, not time. KE₁+PE₁ = KE₂+PE₂. Impulse-momentum: use when you know forces and time. J=F·Δt=mΔv. Energy gives speed; impulse gives time-force relationship.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "comparison", topics: ["Energy Methods"] },
  { id: 271, front: "⚠️ EXAM TRAP: Rolling cylinder acceleration", back: "A rolling cylinder does NOT accelerate at g·sinθ down an incline! a = g·sinθ/(1+I/(mR²)). For solid cylinder: a = (2/3)g·sinθ. Energy goes to BOTH translation and rotation.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "tip", topics: ["Rigid Body"] },
  { id: 272, front: "Compare: Underdamped vs. critically damped vs. overdamped", back: "ζ<1 (underdamped): oscillates with decaying amplitude — most common in real systems. ζ=1 (critical): fastest non-oscillatory return. ζ>1 (overdamped): slow, sluggish return. Most exam questions involve underdamped.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "comparison", topics: ["Vibrations"] },

  // --- MECHANICS OF MATERIALS TRAPS ---
  { id: 273, front: "⚠️ EXAM TRAP: Shear and moment diagram — point load creates what?", back: "Point load: jump in V diagram, slope change in M diagram. Distributed load: slope in V, curvature in M. Concentrated moment: jump in M, no change in V. Know these rules cold.", domain: "topic7", domainName: "Mechanics of Materials", category: "tip", topics: ["Beams"] },
  { id: 274, front: "⚠️ EXAM TRAP: Euler buckling — units and K factor", back: "P_cr = π²EI/(KL)². Common mistakes: (1) Wrong K factor — fixed-free=2.0, pin-pin=1.0, fixed-pin=0.7, fixed-fixed=0.5. (2) Using the WRONG I — use the MINIMUM I (weakest axis).", domain: "topic7", domainName: "Mechanics of Materials", category: "tip", topics: ["Columns"] },
  { id: 275, front: "⚠️ EXAM TRAP: Mohr's circle angles", back: "Angles on Mohr's circle are DOUBLE the physical angles. A 45° rotation in real life = 90° on the circle. The maximum shear stress plane is at 45° to the principal stress planes (90° on Mohr's circle).", domain: "topic7", domainName: "Mechanics of Materials", category: "tip", topics: ["Combined Loading"] },
  { id: 276, front: "Compare: Tresca vs. Von Mises yield criteria", back: "Tresca (max shear): τ_max = (σ₁-σ₂)/2 ≥ σ_y/2. Simpler, more conservative. Von Mises (distortion energy): σ_vm = √(σ₁²-σ₁σ₂+σ₂²) ≥ σ_y. More accurate for ductile materials. Von Mises allows ~15% more stress.", domain: "topic7", domainName: "Mechanics of Materials", category: "comparison", topics: ["Combined Loading"] },
  { id: 277, front: "WORKED EXAMPLE: Thin-walled pressure vessel stresses", back: "Cylinder: σ_hoop = pr/t, σ_long = pr/(2t). Hoop is TWICE longitudinal → cylinder bursts along its LENGTH (longitudinal crack). Sphere: σ = pr/(2t) in all directions. This is why spheres are stronger for same material.", domain: "topic7", domainName: "Mechanics of Materials", category: "concept", topics: ["Stress-Strain"] },
  { id: 278, front: "WORKED EXAMPLE: Cantilever beam deflection", back: "End load P, length L: δ_max = PL³/(3EI) at free end, θ_max = PL²/(2EI). UDL w: δ_max = wL⁴/(8EI). Key: deflection ∝ L³ or L⁴ — length dominates!", domain: "topic7", domainName: "Mechanics of Materials", category: "concept", topics: ["Beams"] },

  // --- MATERIAL SCIENCE TRAPS ---
  { id: 279, front: "⚠️ EXAM TRAP: Iron-carbon diagram — eutectic vs. eutectoid", back: "Eutectoid (0.76%C, 727°C): SOLID γ → α + Fe₃C (pearlite). Eutectic (4.3%C, 1148°C): LIQUID → γ + Fe₃C. Don't confuse them! Eutectoid is the one relevant to most steel questions.", domain: "topic8", domainName: "Material Science", category: "tip", topics: ["Phase Diagrams"] },
  { id: 280, front: "Compare: FCC vs. BCC vs. HCP crystal structures", back: "FCC (4 atoms, APF 0.74): Cu, Al, Ni, Au — most ductile, many slip systems. BCC (2 atoms, APF 0.68): Fe(α), Cr, W — strong, DBTT exists. HCP (6 atoms, APF 0.74): Ti, Zn, Mg — limited slip, less ductile.", domain: "topic8", domainName: "Material Science", category: "comparison", topics: ["Crystal Structure"] },
  { id: 281, front: "Compare: Steels — 1018 vs. 1045 vs. 4140 vs. 304SS", back: "1018: low carbon (0.18%C), ductile, weldable. 1045: medium carbon, heat treatable, shafts/gears. 4140: alloy (Cr-Mo), high strength, aircraft parts. 304SS: austenitic stainless, corrosion resistant, non-magnetic.", domain: "topic8", domainName: "Material Science", category: "comparison", topics: ["Material Selection"] },
  { id: 282, front: "⚠️ EXAM TRAP: Lever rule — which composition goes where?", back: "W_α = (C_β - C₀)/(C_β - C_α). The numerator uses the OTHER phase's composition minus the alloy composition. Easy mnemonic: 'opposite arm over total arm' — like a physical lever.", domain: "topic8", domainName: "Material Science", category: "tip", topics: ["Phase Diagrams"] },

  // --- FLUIDS TRAPS ---
  { id: 283, front: "⚠️ EXAM TRAP: Bernoulli assumptions — when does it fail?", back: "Bernoulli requires: (1) steady flow, (2) incompressible, (3) inviscid, (4) along a streamline. If ANY is violated, use the general energy equation instead. Pipe with friction → NOT Bernoulli.", domain: "topic9", domainName: "Fluid Mechanics", category: "tip", topics: ["Fluid Dynamics"] },
  { id: 284, front: "⚠️ EXAM TRAP: Darcy friction factor — what about laminar vs turbulent?", back: "Laminar (Re<2300): f = 64/Re — no Moody chart needed. Turbulent: use Moody chart with Re AND ε/D. Common error: using Moody chart for laminar flow or forgetting relative roughness.", domain: "topic9", domainName: "Fluid Mechanics", category: "tip", topics: ["Pipe Flow"] },
  { id: 285, front: "Compare: Pumps in series vs. parallel", back: "Series: same Q, heads ADD. H_total = H₁+H₂. Use when you need more head. Parallel: same H, flows ADD. Q_total = Q₁+Q₂. Use when you need more flow. System curve intersection gives operating point.", domain: "topic9", domainName: "Fluid Mechanics", category: "comparison", topics: ["Turbomachinery"] },
  { id: 286, front: "WORKED EXAMPLE: Pipe head loss calculation", back: "Water in 100m pipe, D=0.1m, V=2m/s, f=0.02. h_f = f(L/D)(V²/2g) = 0.02(100/0.1)(4/19.62) = 0.02(1000)(0.204) = 4.08m. Always check units and don't forget 2g!", domain: "topic9", domainName: "Fluid Mechanics", category: "concept", topics: ["Pipe Flow"] },
  { id: 287, front: "⚠️ EXAM TRAP: Pump affinity laws — power vs speed", back: "Q∝N, H∝N², P∝N³. Double the speed → 8× the power! Common trap: forgetting the CUBE relationship for power. Also: these only apply for geometrically similar conditions.", domain: "topic9", domainName: "Fluid Mechanics", category: "tip", topics: ["Turbomachinery"] },

  // --- THERMODYNAMICS TRAPS ---
  { id: 288, front: "⚠️ EXAM TRAP: Carnot efficiency — temperatures must be in KELVIN", back: "η_Carnot = 1 - T_L/T_H. If T_H = 500°C and T_L = 27°C: η = 1 - 300/773 = 61.2%. Using °C directly: 1 - 27/500 = 94.6% — WRONG! Always convert to K first.", domain: "topic10", domainName: "Thermodynamics", category: "tip", topics: ["Cycles"] },
  { id: 289, front: "⚠️ EXAM TRAP: Throttling process — what stays constant?", back: "h₁ = h₂ (enthalpy). NOT isentropic (s₂ > s₁). NOT isothermal. NOT isobaric (P drops). Common exam trap: saying a throttle valve is isentropic. It's isenthalpic and IRREVERSIBLE.", domain: "topic10", domainName: "Thermodynamics", category: "tip", topics: ["Properties"] },
  { id: 290, front: "Compare: Otto vs. Diesel vs. Brayton cycles", back: "Otto (gasoline): const-V heat add, η=1-1/r^(γ-1). Diesel: const-P heat add, higher compression, higher η. Brayton (gas turbine): two const-P + two isentropic, η=1-1/r_p^((γ-1)/γ). All improve with higher compression/pressure ratio.", domain: "topic10", domainName: "Thermodynamics", category: "comparison", topics: ["Cycles"] },
  { id: 291, front: "⚠️ EXAM TRAP: Isentropic efficiency — turbine vs compressor formula", back: "Turbine: η_t = (h₁-h₂a)/(h₁-h₂s) — actual/ideal. Compressor: η_c = (h₂s-h₁)/(h₂a-h₁) — ideal/actual. They are INVERTED! Turbine: actual work < ideal. Compressor: actual work > ideal.", domain: "topic10", domainName: "Thermodynamics", category: "tip", topics: ["Cycles"] },
  { id: 292, front: "WORKED EXAMPLE: Steam table lookup", back: "Water at 200kPa, h=2700 kJ/kg. At 200kPa: h_f=504.7, h_fg=2201.6, h_g=2706.3. Since h < h_g → two-phase! x = (h-h_f)/h_fg = (2700-504.7)/2201.6 = 0.997 (nearly saturated vapor).", domain: "topic10", domainName: "Thermodynamics", category: "concept", topics: ["Properties"] },

  // --- HEAT TRANSFER TRAPS ---
  { id: 293, front: "⚠️ EXAM TRAP: Radiation — temperatures must be in KELVIN (absolute)", back: "q = εσA(T₁⁴ - T₂⁴). Using °C gives completely wrong answers because T⁴ amplifies the error enormously. 300K vs 27°C: (300)⁴ = 8.1×10⁹ but (27)⁴ = 531,441. Always use K or R.", domain: "topic11", domainName: "Heat Transfer", category: "tip", topics: ["Radiation"] },
  { id: 294, front: "⚠️ EXAM TRAP: Critical radius of insulation", back: "r_cr = k/h for cylinder. If pipe radius < r_cr, adding insulation INCREASES heat loss (larger surface area wins). Only above r_cr does insulation reduce heat loss. This surprises most students.", domain: "topic11", domainName: "Heat Transfer", category: "tip", topics: ["Conduction"] },
  { id: 295, front: "Compare: LMTD method vs. ε-NTU method", back: "LMTD: all 4 temperatures known → find area (design). q=UA·LMTD. ε-NTU: area/UA known, find outlet temps (rating). ε=q/q_max. Both give same answer — choose based on what's known vs. unknown.", domain: "topic11", domainName: "Heat Transfer", category: "comparison", topics: ["Heat Exchangers"] },
  { id: 296, front: "Compare: Conduction vs Convection vs Radiation", back: "Conduction: through solid/fluid, needs medium, q=-kA(dT/dx). Convection: fluid motion, q=hA(T_s-T_∞). Radiation: electromagnetic waves, no medium needed, q=εσAT⁴. All three may occur simultaneously.", domain: "topic11", domainName: "Heat Transfer", category: "comparison", topics: ["Conduction"] },
  { id: 297, front: "⚠️ EXAM TRAP: Biot number — when to use lumped capacitance", back: "Bi = hL_c/k_SOLID (not k_fluid!). L_c = V/A_s. If Bi < 0.1: uniform temperature inside body (lumped system). If Bi > 0.1: significant internal ΔT — need Heisler charts or numerical methods.", domain: "topic11", domainName: "Heat Transfer", category: "tip", topics: ["Conduction"] },

  // --- CONTROLS TRAPS ---
  { id: 298, front: "⚠️ EXAM TRAP: Open-loop vs closed-loop transfer function", back: "Open-loop: G(s)H(s). Closed-loop: G(s)/(1+G(s)H(s)) for negative feedback. Common error: using the wrong one. Stability analysis uses open-loop. System response uses closed-loop.", domain: "topic12", domainName: "Measurements & Controls", category: "tip", topics: ["Controls"] },
  { id: 299, front: "Compare: RTD vs Thermocouple vs Thermistor", back: "RTD (Pt100): most accurate, stable, slow, needs excitation. Thermocouple: wide range (-200 to 2000°C), self-powered, less accurate. Thermistor: very sensitive, limited range, nonlinear. Choose based on application.", domain: "topic12", domainName: "Measurements & Controls", category: "comparison", topics: ["Sensors"] },
  { id: 300, front: "WORKED EXAMPLE: First-order step response", back: "G(s)=5/(2s+1). Step input R=1. τ=2s, K=5. y(t)=5(1-e^(-t/2)). At t=2s: y=5(1-0.368)=3.16 (63.2%). At t=10s: y≈5 (99.3%). Final value = K×step = 5.", domain: "topic12", domainName: "Measurements & Controls", category: "concept", topics: ["Controls"] },

  // --- MECHANICAL DESIGN TRAPS ---
  { id: 301, front: "⚠️ EXAM TRAP: Bolt preload — what fraction of external load does the bolt see?", back: "F_bolt = F_i + C·P where C = k_b/(k_b+k_m) ≈ 0.2. The bolt sees only ~20% of the external load! The joint (members) absorbs ~80%. Without preload, the bolt sees 100% — preload is critical.", domain: "topic13", domainName: "Mechanical Design", category: "tip", topics: ["Fasteners"] },
  { id: 302, front: "⚠️ EXAM TRAP: Bearing life — the exponent matters", back: "Ball bearings: L₁₀ = (C/P)³. Roller bearings: L₁₀ = (C/P)^(10/3). The exponents are DIFFERENT. Common exam error: using exponent 3 for roller bearings. Read the problem carefully.", domain: "topic13", domainName: "Mechanical Design", category: "tip", topics: ["Bearings"] },
  { id: 303, front: "Compare: Goodman vs Soderberg vs Gerber fatigue criteria", back: "Goodman: σ_a/S_e + σ_m/S_ut = 1 (linear, most common on FE). Soderberg: uses S_y instead of S_ut (more conservative). Gerber: parabolic (σ_a/S_e + (σ_m/S_ut)² = 1, less conservative). FE exam usually uses Goodman.", domain: "topic13", domainName: "Mechanical Design", category: "comparison", topics: ["Fatigue"] },
  { id: 304, front: "⚠️ EXAM TRAP: K_f vs K_t in fatigue", back: "K_t = theoretical stress concentration (from geometry charts). K_f = fatigue stress concentration = 1+q(K_t-1), where q = notch sensitivity. Apply K_f to ALTERNATING stress only, NOT mean stress (in Goodman).", domain: "topic13", domainName: "Mechanical Design", category: "tip", topics: ["Fatigue"] },
  { id: 305, front: "Compare: Spur vs Helical vs Bevel vs Worm gears", back: "Spur: parallel axes, simple, noisy at high speed. Helical: parallel axes, quieter, axial thrust. Bevel: intersecting axes (90° turn). Worm: non-intersecting, high ratio, often self-locking, low efficiency.", domain: "topic13", domainName: "Mechanical Design", category: "comparison", topics: ["Gears"] },
  { id: 306, front: "WORKED EXAMPLE: Shaft diameter for combined loading", back: "M=500N·m, T=300N·m, S_y=250MPa, n=2. d³ = (16n/πS_y)√(M²+T²) = (16×2/(π×250×10⁶))√(500²+300²) = (32/(785.4×10⁶))×583.1 = 23.7×10⁻⁶ → d = 28.7mm → use 30mm.", domain: "topic13", domainName: "Mechanical Design", category: "concept", topics: ["Shafts"] },

  // --- MANUFACTURING TRAPS ---
  { id: 307, front: "⚠️ EXAM TRAP: Taylor tool life — doubling speed effect", back: "VT^n = C. If n=0.25 (carbide) and V doubles: T_new/T_old = (V_old/V_new)^(1/n) = (1/2)^4 = 1/16. Tool life drops to 1/16th! Small speed increase → large life decrease.", domain: "topic14", domainName: "Manufacturing", category: "tip", topics: ["Machining"] },
  { id: 308, front: "Compare: Casting vs Forging vs Machining", back: "Casting: complex shapes, any size, poor mechanical properties, rough surface. Forging: superior grain structure/strength, limited shapes, high cost. Machining: tight tolerances, good finish, material waste, any shape.", domain: "topic14", domainName: "Manufacturing", category: "comparison", topics: ["Forming"] },
  { id: 309, front: "⚠️ EXAM TRAP: GD&T — MMC bonus tolerance", back: "At MMC (shaft at max, hole at min), geometric tolerance is as specified. As feature departs from MMC, BONUS tolerance = departure from MMC. Total allowed = stated tolerance + bonus. Only applies with Ⓜ modifier.", domain: "topic14", domainName: "Manufacturing", category: "tip", topics: ["Tolerancing"] },
  { id: 310, front: "Compare: Clearance fit vs Transition fit vs Interference fit", back: "Clearance: shaft always smaller than hole (free movement). Transition: may be tight or loose (light press/sliding). Interference: shaft always larger (press fit, permanent assembly). Check hole/shaft tolerance ranges.", domain: "topic14", domainName: "Manufacturing", category: "comparison", topics: ["Tolerancing"] },

  // --- MANAGEMENT TRAPS ---
  { id: 311, front: "⚠️ EXAM TRAP: Critical path — adding float to ALL activities", back: "Only activities ON the critical path have zero float. Non-critical activities have positive float. Crashing a non-critical activity does NOT shorten the project! Only crash critical path activities.", domain: "topic15", domainName: "Engineering Management", category: "tip", topics: ["Project Management"] },
  { id: 312, front: "Compare: Cp vs Cpk", back: "Cp = (USL-LSL)/(6σ) — potential capability if perfectly centered. Cpk = min[(USL-μ)/(3σ), (μ-LSL)/(3σ)] — actual capability. If Cp >> Cpk → process is off-center, just needs re-centering.", domain: "topic15", domainName: "Engineering Management", category: "comparison", topics: ["Quality"] },
  { id: 313, front: "WORKED EXAMPLE: PERT expected time and variance", back: "a=4, m=6, b=14 days. t_e = (4+4×6+14)/6 = 42/6 = 7 days. σ² = ((14-4)/6)² = (10/6)² = 2.78 days². σ = 1.67 days. Use these for probability calculations on the critical path.", domain: "topic15", domainName: "Engineering Management", category: "concept", topics: ["Project Management"] },

  // --- CROSS-TOPIC EXAM STRATEGY CARDS ---
  { id: 314, front: "FE Exam Strategy: Unit conversion traps", back: "Always check: kPa vs MPa (factor of 1000), mm vs m (factor of 1000), mm² vs m² (factor of 10⁶), rpm vs rad/s (×2π/60). Most wrong answers on the FE are correct calculations with unit errors.", domain: "topic0", domainName: "Mathematics", category: "tip", topics: ["Exam Strategy"] },
  { id: 315, front: "FE Exam Strategy: When you're stuck on a multiple choice", back: "1) Check units — eliminate answers with wrong units. 2) Check order of magnitude. 3) Try extreme cases (what if x→0 or x→∞?). 4) Plug the answer back in to verify. Don't leave blanks — no penalty for guessing.", domain: "topic0", domainName: "Mathematics", category: "tip", topics: ["Exam Strategy"] },

  // --- MORE DEPTH CARDS FOR WEAKER TOPICS ---
  { id: 316, front: "What is the Euler turbomachine equation?", back: "ΔH = (U₂V_θ₂ - U₁V_θ₁)/g. Fundamental for pump/turbine design. U = blade speed, V_θ = tangential fluid velocity. Positive ΔH = pump; negative = turbine.", domain: "topic9", domainName: "Fluid Mechanics", category: "formula", topics: ["Turbomachinery"] },
  { id: 317, front: "What is the Buckingham Pi theorem?", back: "If n variables involve m fundamental dimensions, they can form k = n-m independent dimensionless groups (Π groups). Essential for dimensional analysis and similitude.", domain: "topic9", domainName: "Fluid Mechanics", category: "concept", topics: ["Fluid Dynamics"] },
  { id: 318, front: "What is the Mach number?", back: "Ma = V/c where c = √(γRT) for ideal gas. Ma < 1: subsonic. Ma = 1: sonic. Ma > 1: supersonic. Compressibility matters when Ma > 0.3.", domain: "topic9", domainName: "Fluid Mechanics", category: "definition", topics: ["Fluid Dynamics"] },
  { id: 319, front: "What is the polytropic process PVⁿ = C?", back: "n=0: isobaric. n=1: isothermal. n=γ: isentropic. n=∞: isochoric. General case includes all standard processes as special cases.", domain: "topic10", domainName: "Thermodynamics", category: "concept", topics: ["Laws"] },
  { id: 320, front: "What is the exergy (availability) concept?", back: "Maximum useful work as system reaches equilibrium with surroundings. ψ = (u-u₀) + P₀(v-v₀) - T₀(s-s₀). Destroyed by irreversibilities. Measures energy 'quality'.", domain: "topic10", domainName: "Thermodynamics", category: "definition", topics: ["Laws"] },
  { id: 321, front: "What is Wien's displacement law?", back: "λ_max·T = 2898 μm·K. Hotter objects peak at shorter wavelengths. Sun (5800K): ~0.5μm (visible). Room temp (300K): ~10μm (infrared).", domain: "topic11", domainName: "Heat Transfer", category: "formula", topics: ["Radiation"] },
  { id: 322, front: "What is the Routh-Hurwitz stability criterion?", back: "Arrange characteristic polynomial coefficients in Routh array. ALL first-column elements must be positive for stability. Number of sign changes = number of unstable poles.", domain: "topic12", domainName: "Measurements & Controls", category: "concept", topics: ["Controls"] },
  { id: 323, front: "What is gain margin and phase margin?", back: "Gain margin: at ω where phase=-180°, how much gain increase before instability. Phase margin: at ω where |G|=0dB, how much phase decrease before instability. Both should be positive.", domain: "topic12", domainName: "Measurements & Controls", category: "definition", topics: ["Controls"] },
  { id: 324, front: "What is the weld throat area for a fillet weld?", back: "Throat = 0.707 × leg size. Effective area = throat × weld length. Shear stress: τ = F/(0.707·w·L). Always use THROAT, not leg, for stress calculations.", domain: "topic13", domainName: "Mechanical Design", category: "formula", topics: ["Fasteners"] },
  { id: 325, front: "What is the hertz contact stress in gears?", back: "σ_H = C_p√(W_t·K_factors/(d·F·I)). Surface pitting failure occurs when σ_H exceeds the allowable contact stress. Different from Lewis bending stress.", domain: "topic13", domainName: "Mechanical Design", category: "formula", topics: ["Gears"] },
  { id: 326, front: "What is creep in materials?", back: "Time-dependent plastic deformation under constant stress at elevated T (>0.4·T_melt). Three stages: primary (decreasing rate), secondary (steady, for design), tertiary (accelerating to rupture).", domain: "topic8", domainName: "Material Science", category: "definition", topics: ["Mechanical Properties"] },
  { id: 327, front: "What are the four strengthening mechanisms for metals?", back: "1) Grain refinement (Hall-Petch). 2) Solid solution strengthening. 3) Strain/work hardening (cold work). 4) Precipitation hardening (age hardening). All impede dislocation motion.", domain: "topic8", domainName: "Material Science", category: "concept", topics: ["Strengthening"] },
  { id: 328, front: "What is the Clausius statement of the 2nd law?", back: "Heat cannot spontaneously flow from a cold body to a hot body without external work input. This is why refrigerators need power. Equivalent to Kelvin-Planck statement.", domain: "topic10", domainName: "Thermodynamics", category: "definition", topics: ["Laws"] },
  { id: 329, front: "Compare: Forced convection correlations — flat plate vs pipe", back: "Flat plate laminar: Nu=0.332Re^½Pr^⅓ (local). Pipe turbulent: Nu=0.023Re^0.8Pr^n (Dittus-Boelter). Pipe laminar: Nu=3.66 (const T_w). Different geometries → different correlations.", domain: "topic11", domainName: "Heat Transfer", category: "comparison", topics: ["Convection"] },
  { id: 330, front: "What is EDM and when is it used?", back: "Electrical Discharge Machining: sparks erode conductive material in dielectric fluid. For: hard materials, complex shapes, sharp corners. Slow MRR, workpiece must be conductive.", domain: "topic14", domainName: "Manufacturing", category: "definition", topics: ["Machining"] },

  // --- ADDITIONAL HIGH-VALUE CARDS ---
  { id: 331, front: "What is the EVM formula for estimate at completion (EAC)?", back: "EAC = BAC/CPI. Budget At Completion divided by Cost Performance Index. If CPI = 0.8, project will cost 25% more than budgeted.", domain: "topic15", domainName: "Engineering Management", category: "formula", topics: ["Project Management"] },
  { id: 332, front: "What is the MTBF reliability formula?", back: "R(t) = e^(-t/MTBF) = e^(-λt). MTBF = 1/λ. At t = MTBF: R = e^(-1) = 36.8%. Only 36.8% survive to their MTBF — this surprises most students.", domain: "topic15", domainName: "Engineering Management", category: "formula", topics: ["Quality"] },
  { id: 333, front: "Compare: X-bar chart vs R chart vs p chart", back: "X-bar: monitors process mean (variable data, subgroups). R chart: monitors process spread/variability. p chart: monitors proportion defective (attribute data). Use the right chart for the data type.", domain: "topic15", domainName: "Engineering Management", category: "comparison", topics: ["Quality"] },
  { id: 334, front: "What is the Stokes drag law?", back: "F_D = 3πμVd for Re << 1 (creeping flow, small particles). C_D = 24/Re. Used for: settling of fine particles, viscometry, filtration. Only valid for very low Reynolds numbers.", domain: "topic9", domainName: "Fluid Mechanics", category: "formula", topics: ["External Flow"] },
  { id: 335, front: "What is thermal stress in a restrained bar?", back: "σ = EαΔT. If heated: compressive (bar wants to expand but can't). If cooled: tensile. α = coefficient of thermal expansion. Common in constrained structures, bridges, rail tracks.", domain: "topic7", domainName: "Mechanics of Materials", category: "formula", topics: ["Stress-Strain"] },
  { id: 336, front: "Compare: Pin, roller, and fixed supports", back: "Pin: 2 reactions (Fx, Fy), allows rotation. Roller: 1 reaction (⊥ to surface), allows rotation and translation along surface. Fixed: 3 reactions (Fx, Fy, M), no movement. Total unknowns determines if determinate.", domain: "topic5", domainName: "Statics", category: "comparison", topics: ["Equilibrium"] },
  { id: 337, front: "What is the difference between plane stress and plane strain?", back: "Plane stress: σ_z=0 (thin plates, free surfaces). ε_z ≠ 0. Plane strain: ε_z=0 (thick/long bodies, dams). σ_z ≠ 0. Don't confuse which quantity is zero in each case.", domain: "topic7", domainName: "Mechanics of Materials", category: "comparison", topics: ["Combined Loading"] },
  { id: 338, front: "What is the continuity equation for compressible flow?", back: "ρ₁A₁V₁ = ρ₂A₂V₂ (mass flow rate constant). For incompressible (ρ=const): simplifies to A₁V₁ = A₂V₂. Compressible flow adds density variation.", domain: "topic9", domainName: "Fluid Mechanics", category: "formula", topics: ["Fluid Dynamics"] },
  { id: 339, front: "What is regenerative braking in a Rankine cycle context?", back: "Feedwater heating: extract steam from turbine at intermediate pressure to preheat feedwater. Reduces fuel needed. Increases average T of heat addition → higher efficiency.", domain: "topic10", domainName: "Thermodynamics", category: "concept", topics: ["Cycles"] },
  { id: 340, front: "⚠️ EXAM TRAP: Simply supported beam — max deflection location", back: "For UNIFORM load: max deflection at center (5wL⁴/384EI). For CENTER point load: also at center (PL³/48EI). For OFF-CENTER point load: max deflection is NOT at the load — it's slightly toward the nearer support.", domain: "topic7", domainName: "Mechanics of Materials", category: "tip", topics: ["Beams"] },
  { id: 341, front: "What is Miner's rule for cumulative fatigue?", back: "Σ(n_i/N_i) = 1 at failure. Each stress level consumes a fraction of fatigue life. n_i = cycles at stress level i, N_i = cycles to failure at that stress. Linear damage accumulation (approximate).", domain: "topic13", domainName: "Mechanical Design", category: "formula", topics: ["Fatigue"] },
  { id: 342, front: "What is surface roughness Ra?", back: "Arithmetic average roughness: average absolute deviation from the mean line. Typical: ground 0.4-1.6μm, turned 1.6-6.3μm, milled 1.6-12.5μm, polished <0.4μm. Affects fatigue, friction, sealing.", domain: "topic14", domainName: "Manufacturing", category: "definition", topics: ["Tolerancing"] },
  { id: 343, front: "What is the fin effectiveness criterion?", back: "ε_fin = q_with_fin / q_without_fin. If ε_fin < 2, the fin is not worth adding. Fins are most effective on the side with LOWER h (usually air side, not water side).", domain: "topic11", domainName: "Heat Transfer", category: "concept", topics: ["Conduction"] },
  { id: 344, front: "What does the Fourier number represent?", back: "Fo = αt/L². Dimensionless time in transient conduction. Ratio of heat conducted to heat stored. Higher Fo → closer to steady state. Appears in Heisler chart solutions.", domain: "topic11", domainName: "Heat Transfer", category: "definition", topics: ["Conduction"] },
  { id: 345, front: "⚠️ EXAM TRAP: Specific heat ratio γ for air", back: "γ = c_p/c_v = 1.4 for air (diatomic gas at moderate T). c_p = 1.005 kJ/(kg·K), c_v = 0.718, R = 0.287. Don't confuse R_air with R_universal = 8.314 J/(mol·K).", domain: "topic10", domainName: "Thermodynamics", category: "tip", topics: ["Properties"] },
  { id: 346, front: "What is a free body diagram (FBD) checklist?", back: "1) Isolate the body. 2) Draw ALL external forces: weight, applied loads, reactions. 3) Label magnitudes/directions. 4) Add coordinate axes. 5) Do NOT include internal forces. Missing a force = wrong answer.", domain: "topic5", domainName: "Statics", category: "tip", topics: ["Equilibrium"] },
  { id: 347, front: "What is the difference between static and dynamic loading in fatigue?", back: "Static: constant load → yield or ultimate failure. Dynamic/cyclic: repeated loading below ultimate → fatigue crack → fracture. 90% of mechanical failures are fatigue. S-N curve governs dynamic life.", domain: "topic13", domainName: "Mechanical Design", category: "comparison", topics: ["Fatigue"] },
  { id: 348, front: "What are the common beam deflection formulas to memorize?", back: "Simply supported, center load: PL³/(48EI). Simply supported, UDL: 5wL⁴/(384EI). Cantilever, end load: PL³/(3EI). Cantilever, UDL: wL⁴/(8EI). These cover most FE beam problems.", domain: "topic7", domainName: "Mechanics of Materials", category: "tip", topics: ["Beams"] },
  { id: 349, front: "What is the hydraulic diameter?", back: "D_h = 4A/P (4 × cross-sectional area / wetted perimeter). For non-circular ducts, use D_h in place of D in Re and friction factor calculations. Circle: D_h = D.", domain: "topic9", domainName: "Fluid Mechanics", category: "formula", topics: ["Pipe Flow"] },
  { id: 350, front: "What is Dalton's law of partial pressures?", back: "P_total = ΣP_i. Each gas exerts pressure as if it alone occupied the container. P_i = y_i·P_total (mole fraction × total pressure). Fundamental for gas mixtures and psychrometrics.", domain: "topic10", domainName: "Thermodynamics", category: "formula", topics: ["Mixtures"] },
  { id: 351, front: "⚠️ EXAM TRAP: Series springs vs parallel springs", back: "Series: 1/k_eq = 1/k₁+1/k₂ (softer, same force, deflections add). Parallel: k_eq = k₁+k₂ (stiffer, same deflection, forces add). OPPOSITE of electrical resistors — don't mix them up!", domain: "topic6", domainName: "Dynamics & Vibrations", category: "tip", topics: ["Vibrations"] },
  { id: 352, front: "What is the relationship between Young's modulus and material stiffness?", back: "E = σ/ε (slope of linear elastic region). Steel E≈200GPa, Al≈70GPa, Cu≈120GPa. E is a MATERIAL property — independent of geometry. Stiffness k = AE/L depends on geometry.", domain: "topic7", domainName: "Mechanics of Materials", category: "concept", topics: ["Stress-Strain"] },
  { id: 353, front: "What are the key dimensionless numbers in heat transfer?", back: "Re = inertia/viscous. Pr = momentum/thermal diffusivity. Nu = convective/conductive HT. Gr = buoyancy/viscous. Ra = Gr·Pr. Bi = internal/external resistance. Fo = conduction time.", domain: "topic11", domainName: "Heat Transfer", category: "concept", topics: ["Convection"] },
  { id: 354, front: "What is the FE ME exam format?", back: "110 questions, 5 hours 20 minutes (320 min). ~2.9 min/question. CBT format with digital reference handbook. 16 topic areas weighted differently. Pass/fail (~50-60% estimated). No penalty for guessing.", domain: "topic3", domainName: "Ethics", category: "tip", topics: ["Exam Strategy"] },

  // ═══════════════════════════════════════════════════════════════
  // DEEP CONCEPTUAL FLASHCARDS — CISSP-QUALITY DEPTH (150+ cards)
  // ═══════════════════════════════════════════════════════════════

  // --- MATHEMATICS: Deep Conceptual ---
  { id: 355, front: "Explain: Why does the chain rule work conceptually?", back: "The chain rule d/dx[f(g(x))] = f'(g(x))·g'(x) works because when you change x by dx, the inner function g changes by g'(x)dx, and then f changes by f'(g)·(change in g). You're multiplying rates of change: the rate f changes with respect to g, times the rate g changes with respect to x. Think of it as unit cancellation: (df/dg)·(dg/dx) = df/dx.", domain: "topic0", domainName: "Mathematics", category: "concept", topics: ["Calculus"] },
  { id: 356, front: "Explain: What does an eigenvalue physically represent?", back: "An eigenvalue λ represents a scaling factor: when matrix A acts on eigenvector v, the vector's direction doesn't change — it only stretches (or shrinks) by factor λ. In engineering: eigenvalues give natural frequencies of vibrating systems (ω² = λ), critical buckling loads, and stability characteristics. Zero eigenvalue → singular matrix. Negative eigenvalue → direction reversal.", domain: "topic0", domainName: "Mathematics", category: "concept", topics: ["Linear Algebra"] },
  { id: 357, front: "Compare: Euler vs. Runge-Kutta for ODE solving", back: "Euler: y_{n+1} = y_n + h·f(t_n, y_n). Simplest, first-order accurate (error ∝ h). Fast but inaccurate unless h is very small. Runge-Kutta (RK4): uses 4 slope evaluations per step, fourth-order accurate (error ∝ h⁴). Much more accurate for same step size but 4× the computation. RK4 is the standard engineering ODE solver. Use Euler only for conceptual understanding.", domain: "topic0", domainName: "Mathematics", category: "comparison", topics: ["Numerical Methods"] },
  { id: 358, front: "WORKED EXAMPLE: Determine if ∫₁^∞ 1/x² dx converges", back: "∫₁^∞ 1/x² dx = lim(b→∞) [-1/x]₁^b = lim(b→∞) (-1/b + 1) = 0 + 1 = 1. Converges to 1. Compare: ∫₁^∞ 1/x dx = lim(b→∞) [ln x]₁^b = ∞. Diverges! The p-test: ∫₁^∞ 1/x^p dx converges if p > 1, diverges if p ≤ 1. So 1/x² (p=2) converges, 1/x (p=1) diverges.", domain: "topic0", domainName: "Mathematics", category: "concept", topics: ["Calculus"] },
  { id: 359, front: "Explain: What is a saddle point and how to detect it?", back: "A saddle point is a critical point where f_x = f_y = 0, but it's neither a local max nor min — it curves up in one direction and down in another (like a horse saddle). Detection: compute the discriminant D = f_xx·f_yy − (f_xy)² at the critical point. If D < 0 → saddle point. If D > 0 and f_xx > 0 → local min. If D > 0 and f_xx < 0 → local max. If D = 0 → inconclusive.", domain: "topic0", domainName: "Mathematics", category: "concept", topics: ["Calculus"] },

  // --- PROBABILITY: Deep Conceptual ---
  { id: 360, front: "Explain: Why divide by n-1 (not n) for sample variance?", back: "Dividing by n-1 instead of n corrects for bias — it gives an 'unbiased estimator' of the population variance. With n observations, you've already used one degree of freedom to estimate the mean (x̄), leaving only n-1 independent pieces of information for estimating spread. This is called Bessel's correction. The effect is small for large n but significant for small samples (which is when it matters most).", domain: "topic1", domainName: "Probability & Statistics", category: "concept", topics: ["Descriptive Statistics"] },
  { id: 361, front: "Compare: Type I error vs Type II error — which is worse?", back: "Type I (α, false positive): rejecting H₀ when it's true. 'Crying wolf.' Controlled by significance level (typically α = 0.05). Type II (β, false negative): failing to reject H₀ when it's false. 'Missing a real effect.' Which is worse depends on context: in medical testing, Type II (missing a disease) could be fatal. In quality control, Type I (scrapping good parts) wastes money. The FE exam tests your understanding of both, not which is 'worse.'", domain: "topic1", domainName: "Probability & Statistics", category: "comparison", topics: ["Hypothesis Testing"] },
  { id: 362, front: "Explain: Central Limit Theorem — why it matters for engineers", back: "The CLT says the sampling distribution of the mean approaches normal as sample size increases, REGARDLESS of the population distribution. This is profound because: (1) we can use normal distribution z-tables even for non-normal data, (2) quality control charts work because sample means are normally distributed, (3) confidence intervals and hypothesis tests are valid for large n even with skewed populations. Rule of thumb: n ≥ 30 is usually sufficient for the CLT to apply.", domain: "topic1", domainName: "Probability & Statistics", category: "concept", topics: ["Distributions"] },

  // --- STATICS: Deep Conceptual ---
  { id: 363, front: "Explain: Why does a three-force body have concurrent or parallel forces?", back: "For a body in equilibrium under exactly 3 forces: if the forces are NOT parallel, they MUST be concurrent (all three lines of action pass through a single point). Proof: take moments about the intersection of any two forces — only the third force has a moment arm. For equilibrium ΣM = 0, the third force must also pass through that point. This principle lets you find force directions without writing equations — just find the intersection point.", domain: "topic5", domainName: "Statics", category: "concept", topics: ["Equilibrium"] },
  { id: 364, front: "Explain: Why are I-beams more efficient than solid rectangles?", back: "Bending resistance depends on moment of inertia I, which weights area by distance² from the neutral axis. I-beams concentrate material in the flanges (far from center) where it contributes most to I via the Ad² term. A solid rectangle wastes material near the neutral axis where stress is low. An I-beam with the same weight as a solid rectangle can have 3-5× higher I, meaning 3-5× more bending resistance. This is why structural steel is rolled into W-shapes, channels, and angles.", domain: "topic5", domainName: "Statics", category: "concept", topics: ["Centroids"] },

  // --- DYNAMICS: Deep Conceptual ---
  { id: 365, front: "Explain: Conservation of energy vs. conservation of momentum — when to use each", back: "Energy conservation (KE₁+PE₁ = KE₂+PE₂): use when ALL forces are conservative (gravity, springs). Fails when friction, impacts, or explosions occur — energy is 'lost' to heat/deformation. Momentum conservation (m₁v₁+m₂v₂ = m₁v₁'+m₂v₂'): use when external forces are zero or negligible during the event (collisions, explosions). Both conserved in perfectly elastic collisions. Only momentum conserved in inelastic collisions. Choose based on what's happening physically.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "comparison", topics: ["Energy Methods"] },
  { id: 366, front: "Explain: Why does a spinning ice skater speed up when pulling arms in?", back: "Conservation of angular momentum: H = Iω = constant (no external torques). When the skater pulls arms in, I decreases (mass closer to axis). Since Iω must stay constant, ω increases. Quantitatively: if I drops by half (I₂ = I₁/2), ω doubles. KE = ½Iω² = ½(I₁/2)(2ω₁)² = I₁ω₁² = 2(½I₁ω₁²) → KE doubles! The extra energy comes from the work done by the skater's muscles pulling the arms inward.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "concept", topics: ["Kinetics"] },
  { id: 367, front: "Explain: Why is resonance dangerous in engineering?", back: "At resonance (ω_forcing ≈ ω_natural), the system absorbs maximum energy from the forcing function. With light damping, amplitudes become very large — theoretically infinite with zero damping. Real-world failures: Tacoma Narrows Bridge (1940, wind-induced resonance), turbine blade fatigue, building collapse during earthquakes matching natural frequency. Engineers avoid resonance by: (1) ensuring ω_operating ≠ ω_n (tune the system), (2) adding damping, (3) designing for ω/ω_n > √2 (vibration isolation).", domain: "topic6", domainName: "Dynamics & Vibrations", category: "concept", topics: ["Vibrations"] },

  // --- MECHANICS OF MATERIALS: Deep Conceptual ---
  { id: 368, front: "Explain: Why does a beam have zero stress at the neutral axis?", back: "During bending, the top fibers compress (shorter) and the bottom fibers stretch (longer). Somewhere in between, there's a surface that neither compresses nor stretches — this is the neutral axis (NA). Since ε = 0 at the NA, and σ = Eε, the stress is also zero there. The NA passes through the centroid of the cross-section for symmetric bending. Above the NA: one sign of stress. Below: the opposite. Maximum stress occurs at the extreme fibers (farthest from NA): σ_max = Mc/I.", domain: "topic7", domainName: "Mechanics of Materials", category: "concept", topics: ["Beams"] },
  { id: 369, front: "Explain: Mohr's circle — what does it represent physically?", back: "Mohr's circle is a graphical representation of ALL possible stress states at a point as you rotate the element through different angles. Every point on the circle represents the (σ, τ) combination on a particular plane. The rightmost point = σ₁ (max principal, zero shear). Leftmost = σ₂ (min principal, zero shear). Top/bottom = ±τ_max (max shear). As you rotate the physical element by θ, you move around the circle by 2θ. The circle makes stress transformation visual and intuitive.", domain: "topic7", domainName: "Mechanics of Materials", category: "concept", topics: ["Combined Loading"] },
  { id: 370, front: "Explain: Why does Euler buckling depend on E but not σ_y?", back: "Euler buckling is an elastic stability problem, not a strength problem. The column doesn't fail because the material is overstressed — it fails because the equilibrium configuration becomes unstable. P_cr = π²EI/(KL)² depends on stiffness (EI), not strength (σ_y). Stiffer material (higher E) resists buckling better. A rubber column with high σ_y but low E would buckle easily. Euler's formula only applies when σ_cr = P_cr/A < σ_y — otherwise the material yields before it can buckle (short column behavior).", domain: "topic7", domainName: "Mechanics of Materials", category: "concept", topics: ["Columns"] },
  { id: 371, front: "Explain: Plane stress vs. plane strain — when does each apply?", back: "Plane stress (σ_z = 0): thin bodies with free surfaces (sheet metal, pressure vessel walls, thin plates). The through-thickness stress is zero because the surface is free. But ε_z ≠ 0 — the material does deform in z. Plane strain (ε_z = 0): thick/long bodies where deformation is constrained in one direction (dams, long retaining walls, thick cylinders). The strain is zero but σ_z ≠ 0 because the constraint creates stress. ⚠️ Don't confuse which quantity is zero in each case!", domain: "topic7", domainName: "Mechanics of Materials", category: "concept", topics: ["Stress-Strain"] },

  // --- MATERIAL SCIENCE: Deep Conceptual ---
  { id: 372, front: "Explain: Why do BCC metals have a ductile-to-brittle transition temperature (DBTT)?", back: "BCC metals (steel, tungsten, chromium) have limited slip systems at low temperatures. As temperature drops, dislocation motion becomes harder, and the material can't deform plastically before fracture — it becomes brittle. FCC metals (aluminum, copper) don't have a DBTT because they have many slip systems that remain active at all temperatures. The Charpy impact test measures this transition. Engineering implication: steel structures in cold climates must use steels with DBTT below operating temperature (e.g., Arctic pipelines).", domain: "topic8", domainName: "Material Science", category: "concept", topics: ["Mechanical Properties"] },
  { id: 373, front: "Explain: What happens at the atomic level during work hardening?", back: "Cold working (plastic deformation below recrystallization temperature) increases dislocation density dramatically — from ~10⁶ to ~10¹² dislocations/cm². These dislocations interact and block each other, creating 'traffic jams' that make further deformation harder. Result: yield strength increases, ductility decreases, hardness increases. Annealing (heating above recrystallization temperature) allows new stress-free grains to nucleate and grow, restoring ductility. This is why sheet metal forming requires intermediate annealing for severe deformations.", domain: "topic8", domainName: "Material Science", category: "concept", topics: ["Crystal Structure"] },

  // --- FLUID MECHANICS: Deep Conceptual ---
  { id: 374, front: "Explain: Why does a turbulent boundary layer delay separation better than laminar?", back: "In a turbulent BL, the random mixing transfers high-momentum fluid from the outer flow toward the wall, keeping the near-wall fluid energized. This extra momentum allows the flow to push farther against an adverse pressure gradient (increasing pressure) before separating. In a laminar BL, the slow-moving near-wall fluid has less momentum and separates earlier. This is why golf balls have dimples — they trip the BL to turbulent, delaying separation, creating a smaller wake, and reducing pressure drag (the 'drag crisis').", domain: "topic9", domainName: "Fluid Mechanics", category: "concept", topics: ["External Flow"] },
  { id: 375, front: "Explain: Why do we need both Bernoulli AND the general energy equation?", back: "Bernoulli (P/ρg + V²/2g + z = const) assumes no viscosity (no friction losses), no energy addition (no pumps), and no energy extraction (no turbines). Real pipe systems violate all three. The general energy equation adds: h_p (pump head), h_t (turbine head), h_L (friction + minor losses). When h_p = h_t = h_L = 0, it reduces to Bernoulli. The FE exam tests both — use Bernoulli for open-flow problems (nozzles, venturis with no significant friction) and general energy for pipe systems.", domain: "topic9", domainName: "Fluid Mechanics", category: "concept", topics: ["Fluid Dynamics"] },

  // --- THERMODYNAMICS: Deep Conceptual ---
  { id: 376, front: "Explain: Why can't a heat engine be 100% efficient?", back: "The Kelvin-Planck statement of the 2nd law: no heat engine can convert ALL heat input to work — some must be rejected to a low-temperature sink. This is because entropy must increase or stay the same in any real process. For 100% efficiency (η = 1 - T_L/T_H = 1), you'd need T_L = 0 K (absolute zero), which is unattainable (3rd law). Even the ideal Carnot engine between 500 K and 300 K is only 40% efficient. Real engines are worse due to irreversibilities (friction, heat transfer across finite ΔT, mixing).", domain: "topic10", domainName: "Thermodynamics", category: "concept", topics: ["Laws"] },
  { id: 377, front: "Explain: Why is counterflow better than parallel flow in heat exchangers?", back: "In counterflow, the hot and cold fluids flow in opposite directions. This means the coldest cold fluid meets the coolest hot fluid, maintaining a temperature difference (driving force) along the entire length. The cold outlet can even exceed the hot outlet temperature (temperature cross). In parallel flow, both fluids enter at the same end — the initial ΔT is large but decreases rapidly. The cold outlet can NEVER exceed the hot outlet. Result: counterflow LMTD is always ≥ parallel flow LMTD → more heat transfer for the same UA → less area needed.", domain: "topic11", domainName: "Heat Transfer", category: "concept", topics: ["Heat Exchangers"] },

  // --- MECHANICAL DESIGN: Deep Conceptual ---
  { id: 378, front: "Explain: Why does bolt preload improve fatigue life?", back: "Without preload, the bolt sees 100% of the external tensile load — it cycles between zero and full load with each application (high stress amplitude). WITH preload F_i, the bolt is already in tension. When external load P is applied, the bolt load only increases by C·P (where C ≈ 0.2). So the bolt fluctuates between F_i and F_i + 0.2P — a much smaller stress range. Since fatigue life depends on stress AMPLITUDE (not mean), reducing the fluctuation dramatically extends life. The joint members absorb ~80% of the load variation.", domain: "topic13", domainName: "Mechanical Design", category: "concept", topics: ["Fasteners"] },
  { id: 379, front: "Explain: Why do gears fail by fatigue (pitting) before they fail by bending?", back: "Gear teeth experience contact (Hertzian) stresses at the pitch line and bending stresses at the root. Contact stresses are compressive and typically much higher than bending stresses (often 3-5×). While compressive stresses don't initiate surface cracks as easily as tensile, the repeated loading creates subsurface fatigue cracks that propagate to the surface, forming pits. Pitting (surface fatigue) is often the life-limiting failure mode. AGMA design checks both bending stress (Lewis equation) and contact stress (Hertz) — the critical one determines the required gear size.", domain: "topic13", domainName: "Mechanical Design", category: "concept", topics: ["Gears"] },
  { id: 380, front: "Explain: Why is shot peening effective for fatigue?", back: "Shot peening blasts the surface with small steel or ceramic balls, plastically deforming a thin surface layer. This creates beneficial COMPRESSIVE residual stresses on the surface (the layer 'wants' to be larger but is constrained by the undeformed interior). Fatigue cracks initiate and propagate in tension — compressive surface stress means cracks can't open, dramatically extending fatigue life. Shot peening can increase fatigue life by 200-300%. It's standard for springs, gear teeth, crankshafts, and any highly stressed cyclically loaded component.", domain: "topic13", domainName: "Mechanical Design", category: "concept", topics: ["Fatigue"] },

  // --- MANUFACTURING: Deep Conceptual ---
  { id: 381, front: "Explain: Why does cutting speed affect tool life exponentially?", back: "Taylor's equation VT^n = C shows that small increases in V cause large decreases in T because n < 1 (typically 0.1-0.5). For HSS (n ≈ 0.125): doubling V → T_new = T_old × (1/2)^(1/0.125) = T_old × (1/2)^8 = T_old/256. Tool life drops by a factor of 256! This is because higher speed → higher temperature → accelerated tool wear (diffusion, oxidation, plastic deformation of the tool). Carbide (higher n ≈ 0.25) is less sensitive: doubling V → T_old/16. Ceramic (n ≈ 0.5) → T_old/4. Higher n = more forgiving of speed changes.", domain: "topic14", domainName: "Manufacturing", category: "concept", topics: ["Machining"] },
  { id: 382, front: "Compare: Sand casting vs Die casting vs Investment casting", back: "Sand casting: low tooling cost, any size, rough surface (Ra ~12-25 μm), loose tolerances (±1-3 mm). Best for: large parts, prototypes, low volume. Die casting: high tooling cost, excellent surface (Ra ~1-3 μm), tight tolerances (±0.1-0.5 mm), fast cycle time. Limited to low-melting alloys (Al, Zn, Mg). Best for: high volume, small-medium parts. Investment (lost wax) casting: medium tooling cost, excellent detail and surface, tight tolerances, any alloy. Best for: complex shapes, aerospace/medical parts. The exam tests knowing which process fits which application.", domain: "topic14", domainName: "Manufacturing", category: "comparison", topics: ["Forming"] },

  // --- CONTROLS: Deep Conceptual ---
  { id: 383, front: "Explain: Why does adding integral action eliminate steady-state error?", back: "The integral term K_i·∫e dt accumulates error over time. Even a tiny persistent error keeps adding to the integral, which grows without bound until the controller output drives the error to zero. The integral 'remembers' past errors and won't stop adjusting until the accumulated error is zero — which only happens when the current error is zero. Downside: integral action can cause overshoot and instability if K_i is too high (integral windup). In practice, anti-windup techniques limit the integral when the actuator saturates.", domain: "topic12", domainName: "Measurements & Controls", category: "concept", topics: ["Controls"] },
  { id: 384, front: "Explain: What does a Bode plot tell you about system behavior?", back: "A Bode plot has two graphs: (1) Magnitude |G(jω)| in dB vs. log frequency, (2) Phase ∠G(jω) in degrees vs. log frequency. It reveals: bandwidth (frequency range of effective operation), gain margin and phase margin (stability indicators), resonance peaks (where system amplifies inputs), roll-off rate (how fast the system attenuates high frequencies). In control design, you shape the Bode plot to achieve desired performance. The FE exam mainly tests gain/phase margin reading.", domain: "topic12", domainName: "Measurements & Controls", category: "concept", topics: ["Controls"] },

  // --- ENGINEERING MANAGEMENT: Deep Conceptual ---
  { id: 385, front: "Explain: Why is the critical path the LONGEST path, not the shortest?", back: "The critical path determines the MINIMUM project duration because all paths must complete before the project is done. The longest path takes the most time, so it's the bottleneck — everything else finishes before it. Shortening a non-critical activity doesn't help because the critical path still takes the same time. To shorten the project, you MUST shorten a critical path activity ('crashing'). If you crash too much, a different path may become critical — the critical path can shift! A project can have multiple critical paths simultaneously.", domain: "topic15", domainName: "Engineering Management", category: "concept", topics: ["Project Management"] },
  { id: 386, front: "Explain: Why does Six Sigma target 3.4 DPMO instead of 0?", back: "Zero defects is theoretically impossible in any process with variation. Six Sigma targets 6 standard deviations between the process mean and the nearest specification limit — but includes a 1.5σ long-term shift assumption (processes drift over time). With this shift: 6σ - 1.5σ = 4.5σ effective → 3.4 DPMO. Without the shift (short-term), 6σ would give ~0.002 DPMO. The 1.5σ shift accounts for real-world process drift, tool wear, material variation, and environmental changes. It's a practical engineering compromise, not a mathematical ideal.", domain: "topic15", domainName: "Engineering Management", category: "concept", topics: ["Quality"] },

  // --- ADDITIONAL CROSS-TOPIC WORKED EXAMPLES ---
  { id: 387, front: "WORKED EXAMPLE: Complete shaft design workflow", back: "Given: P = 20 kW, N = 1500 rpm, σ_y = 250 MPa, n = 2. Step 1: T = P/ω = 20,000/(1500×2π/60) = 127.3 N·m. Step 2: Assume simple torsion only: τ_allow = σ_y/(2n) = 62.5 MPa. Step 3: τ = 16T/(πd³) → d³ = 16T/(πτ) = 16(127.3)/(π×62.5) = 10.38×10⁻⁶ → d = 21.8 mm. Round up to d = 25 mm standard size. Step 4: Check with bending if gear/pulley forces known. This is the fundamental shaft sizing workflow used in industry.", domain: "topic13", domainName: "Mechanical Design", category: "concept", topics: ["Shafts"] },
  { id: 388, front: "WORKED EXAMPLE: Heat exchanger sizing with LMTD", back: "Hot fluid: 150°C → 90°C, ṁ_h·c_ph = 2 kW/°C. Cold fluid: 30°C → 70°C. q = 2×(150-90) = 120 kW. Counterflow ΔT₁ = 150-70 = 80°C, ΔT₂ = 90-30 = 60°C. LMTD = (80-60)/ln(80/60) = 20/0.288 = 69.4°C. If U = 500 W/(m²·K): A = q/(U·LMTD) = 120,000/(500×69.4) = 3.46 m². This is the standard design calculation — given temperatures, find area.", domain: "topic11", domainName: "Heat Transfer", category: "concept", topics: ["Heat Exchangers"] },
  { id: 389, front: "WORKED EXAMPLE: Pump selection for a pipe system", back: "Given: Q = 0.01 m³/s, pipe D = 0.1 m, L = 200 m, f = 0.02, Δz = 15 m, minor losses ΣK = 10. V = Q/A = 0.01/(π×0.05²) = 1.27 m/s. Major loss: h_f = f(L/D)(V²/2g) = 0.02(2000)(0.082) = 3.28 m. Minor loss: h_m = ΣK(V²/2g) = 10(0.082) = 0.82 m. Total: h_pump = Δz + h_f + h_m = 15 + 3.28 + 0.82 = 19.1 m. Power: P = ρgQh/η = 1000(9.81)(0.01)(19.1)/0.75 = 2,498 W ≈ 2.5 kW. Select a pump providing ≥19.1 m at 0.01 m³/s.", domain: "topic9", domainName: "Fluid Mechanics", category: "concept", topics: ["Turbomachinery"] },
  { id: 390, front: "WORKED EXAMPLE: Bearing life calculation", back: "Given: ball bearing with C = 25 kN, applied radial load P = 5 kN, shaft speed N = 1800 rpm. L₁₀ = (C/P)³ = (25/5)³ = 5³ = 125 million revolutions. Life in hours: L₁₀h = L₁₀ × 10⁶/(60N) = 125 × 10⁶/(60×1800) = 125,000,000/108,000 = 1,157 hours. For 90% reliability (L₁₀). For 99% reliability: L₁ = 0.21 × L₁₀ = 243 hours. Higher reliability requires oversizing or better bearing selection.", domain: "topic13", domainName: "Mechanical Design", category: "concept", topics: ["Bearings"] },

  // --- MORE EXAM STRATEGY ---
  { id: 391, front: "FE Exam Strategy: How to use the FE Reference Handbook effectively", back: "The digital reference handbook is searchable (Ctrl+F). Before the exam: (1) Read through the entire handbook once to know what's in it. (2) Note page numbers for commonly used sections (beam deflections, Moody chart, steam tables, unit conversions). (3) Practice using the handbook during practice exams. (4) The handbook has FORMULAS but not PROCEDURES — you need to know when and how to apply each formula. (5) Don't waste time deriving what's already in the handbook. (6) Some formulas are in different notation than your textbook — familiarize yourself.", domain: "topic3", domainName: "Ethics", category: "tip", topics: ["Exam Strategy"] },
  { id: 392, front: "FE Exam Strategy: Time management for 110 questions in 320 minutes", back: "~2.9 min/question average, but NOT equally distributed. Quick strategy: (1) First pass (150 min): answer every question you can solve in <2 min. Skip hard ones. (2) Second pass (120 min): return to skipped questions, spend 3-4 min each. (3) Final pass (50 min): guess on remaining, review flagged answers. Target: 80+ questions answered confidently in first pass. (4) No penalty for guessing — NEVER leave a blank. (5) If stuck, eliminate 2 options and guess between the remaining 2 (50% odds).", domain: "topic3", domainName: "Ethics", category: "tip", topics: ["Exam Strategy"] },
  { id: 393, front: "FE Exam Strategy: Unit conversion quick reference", back: "Critical conversions to memorize: 1 hp = 745.7 W = 550 ft·lb/s. 1 kPa = 1000 Pa. 1 MPa = 10⁶ Pa = 1 N/mm². 1 atm = 101.325 kPa = 14.696 psi. 1 BTU = 1055 J. °C to K: add 273.15. °F to °R: add 459.67. 1 ft = 0.3048 m. 1 in = 25.4 mm. 1 lb = 4.448 N. 1 slug = 14.59 kg. The #1 exam error is wrong units — always check dimensions before selecting your answer.", domain: "topic0", domainName: "Mathematics", category: "tip", topics: ["Exam Strategy"] },
  { id: 394, front: "FE Exam Strategy: Most commonly tested formulas by topic", back: "Math: derivatives, definite integrals. Statics: ΣF=0, ΣM=0, parallel axis theorem. Dynamics: v=v₀+at, F=ma, KE=½mv², P=Tω. MoM: σ=P/A, σ=Mc/I, τ=Tc/J, δ=PL/AE, P_cr=π²EI/(KL)². Fluids: Bernoulli, Re=ρVD/μ, h_f=f(L/D)(V²/2g). Thermo: η_Carnot=1-T_L/T_H, PV=nRT. HT: q=kAΔT/L, q=hAΔT, LMTD. Design: L₁₀=(C/P)³, σ_a/S_e+σ_m/S_ut=1/n. These cover ~60% of the exam.", domain: "topic0", domainName: "Mathematics", category: "tip", topics: ["Exam Strategy"] },

  // --- MORE DEEP COMPARISONS ---
  { id: 395, front: "Compare: Elastic modulus E vs Yield strength σ_y vs Ultimate strength σ_ut", back: "E (Young's modulus): stiffness, slope of elastic σ-ε curve. Material property independent of processing. Steel E ≈ 200 GPa always. σ_y (yield strength): onset of permanent deformation. Depends on processing (cold work, heat treatment). Steel σ_y ranges 200-1500 MPa. σ_ut (ultimate tensile strength): maximum engineering stress. Higher than σ_y due to strain hardening. Determines tensile failure. Key: E tells you how much it deflects; σ_y tells you when it permanently deforms; σ_ut tells you when it breaks.", domain: "topic7", domainName: "Mechanics of Materials", category: "comparison", topics: ["Stress-Strain"] },
  { id: 396, front: "Compare: Fourier's law vs Newton's cooling vs Stefan-Boltzmann", back: "Fourier (conduction): q = -kA(dT/dx). Through solids/fluids. Requires a medium. Linear with ΔT. Newton (convection): q = hA(T_s-T_∞). Between surface and flowing fluid. h depends on flow conditions. Linear with ΔT. Stefan-Boltzmann (radiation): q = εσA(T⁴-T_surr⁴). Electromagnetic waves. No medium needed. Proportional to T⁴ (nonlinear!). Dominant at high temperatures. All three may act simultaneously — add their thermal resistances in parallel for combined heat transfer.", domain: "topic11", domainName: "Heat Transfer", category: "comparison", topics: ["Conduction"] },
  { id: 397, front: "Compare: Pressure vessel hoop stress vs longitudinal stress", back: "For a thin-walled cylindrical pressure vessel: Hoop (circumferential): σ_h = pr/t. Longitudinal: σ_L = pr/(2t). Key: σ_h = 2×σ_L. Hoop stress is TWICE the longitudinal stress. Consequence: cylindrical vessels fail along their LENGTH (longitudinal seam), not around their circumference, because the hoop stress that would cause longitudinal cracking is larger. A sphere has σ = pr/(2t) in ALL directions — equal biaxial stress, making spheres the strongest shape per unit material for pressure containment.", domain: "topic7", domainName: "Mechanics of Materials", category: "comparison", topics: ["Stress-Strain"] },
  { id: 398, front: "Compare: Work-energy method vs F=ma for dynamics problems", back: "F = ma: gives full motion history (position, velocity, acceleration at every instant). Requires knowing forces as functions of time or position. Most general but most work. Work-energy (T₁+ΣU=T₂): gives speeds at two positions without the full trajectory. Efficient when you only need final speed. Can't tell you time or intermediate states. Use when: displacement is known, time is not asked for. Example: 'find the speed at the bottom of a hill' → energy. 'Find when the car stops' → F=ma. Choosing correctly saves 2-3 minutes per problem on the FE exam.", domain: "topic6", domainName: "Dynamics & Vibrations", category: "comparison", topics: ["Energy Methods"] },
  { id: 399, front: "Compare: Bernoulli vs Darcy-Weisbach vs Energy equation", back: "Bernoulli: P/ρg + V²/2g + z = const. No friction, no pumps, no turbines. Use for: orifices, venturis, Pitot tubes, open jets. Darcy-Weisbach: h_f = f(L/D)(V²/2g). Calculates friction head loss in pipes. Needs friction factor from Moody chart. Energy equation: P₁/ρg + V₁²/2g + z₁ + h_p = P₂/ρg + V₂²/2g + z₂ + h_L + h_t. The complete tool — includes pumps, turbines, AND losses. Use for: real pipe systems. Bernoulli is a special case when h_p = h_t = h_L = 0.", domain: "topic9", domainName: "Fluid Mechanics", category: "comparison", topics: ["Fluid Dynamics"] },
  { id: 400, front: "Compare: Straight-line vs MACRS vs DDB depreciation", back: "Straight-line: D = (B-S)/n each year. Equal annual deductions. Simplest. MACRS: IRS standard for US tax. Salvage assumed = 0. Predetermined percentages that front-load deductions (accelerated). Half-year convention. Double-declining balance (DDB): D_k = (2/n)×BV_{k-1}. Fastest early deductions. Never go below salvage. Switch to SL when SL gives larger deduction. Tax advantage: accelerated methods (MACRS, DDB) give larger early deductions → higher early tax savings → higher NPV of tax benefits. FE exam usually specifies which method to use.", domain: "topic4", domainName: "Engineering Economics", category: "comparison", topics: ["Depreciation"] },
];

// ═══════════════════════════════════════════════════════════════
// Runtime: generate formula-based flashcards from formula sheets
// ═══════════════════════════════════════════════════════════════

const DOMAIN_NAMES: Record<number, string> = {
  0: 'Mathematics', 1: 'Probability & Statistics', 2: 'Computational Tools',
  3: 'Ethics', 4: 'Engineering Economics', 5: 'Statics',
  6: 'Dynamics & Vibrations', 7: 'Mechanics of Materials', 8: 'Material Science',
  9: 'Fluid Mechanics', 10: 'Thermodynamics', 11: 'Heat Transfer',
  12: 'Measurements & Controls', 13: 'Mechanical Design', 14: 'Manufacturing',
  15: 'Engineering Management',
};

let nextId = FME_FLASHCARDS.length + 1;

for (const sheet of FME_FORMULA_SHEETS) {
  for (const f of sheet.formulas) {
    FME_FLASHCARDS.push({
      id: nextId++,
      front: `What is the formula for ${f.name}?`,
      back: `${f.formula} — ${f.notes}`,
      domain: `topic${sheet.topicId}`,
      domainName: DOMAIN_NAMES[sheet.topicId],
      category: 'formula',
      topics: [sheet.title],
    });
  }
}

// Update the count after generation
FME_FLASHCARD_COUNT = FME_FLASHCARDS.length;

export function getFMEFlashcards(domain?: string): FMEFlashcard[] {
  if (!domain) return FME_FLASHCARDS;
  return FME_FLASHCARDS.filter(c => c.domain === domain);
}
